// Quiz content for Cours26 — Harmonisation DEM : basse donnée et soprano donné

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours26Content { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Identifier la position d'accord d'une note de basse ───────────────────
  { q: "Une note de basse est la fondamentale de l'accord. À quel état est cet accord ?", opts: ["1er renversement", "2e renversement", "État fondamental", "3e renversement"], a: 2, fb: "Quand la basse est la fondamentale de l'accord, l'accord est à l'état fondamental (position de base). C'est la position la plus stable, à privilégier sur les temps forts et aux cadences." },
  { q: "Si la note de basse est la tierce d'un accord, quel renversement est-on ?", opts: ["État fondamental", "1er renversement (accord de sixte)", "2e renversement (6/4)", "Position de quinte"], a: 1, fb: "La tierce à la basse = 1er renversement, noté 'accord de sixte' (chiffrage 6). Par exemple, Do–Mi–Sol avec Mi à la basse donne un accord de Do en 1er renversement." },
  { q: "Si la note de basse est la quinte d'un accord, quel renversement est-on ?", opts: ["État fondamental", "1er renversement", "2e renversement (accord de quarte et sixte)", "Position ouverte"], a: 2, fb: "La quinte à la basse = 2e renversement, noté '6/4' (chiffrage 6 et 4). C'est le renversement le plus instable — il exige une résolution soigneuse, notamment en 6/4 de cadence." },
  { q: "L'accord Do–Mi–Sol avec Sol à la basse correspond à :", opts: ["I à l'état fondamental", "I en 1er renversement", "I en 2e renversement", "V6"], a: 2, fb: "Sol est la quinte de l'accord de Do majeur. Sol à la basse = 2e renversement = I6/4 (Do 6/4). Cet accord est très instable et se rencontre principalement comme 6/4 de cadence." },
  { q: "L'accord Sol–Si–Ré avec Si à la basse est :", opts: ["V à l'état fondamental", "V6 (1er renversement de V)", "V6/4 (2e renversement)", "VII à l'état fondamental"], a: 1, fb: "Si est la tierce de l'accord de Sol majeur. Si à la basse = 1er renversement de V = V6. Ce renversement est très courant et donne une basse conjointe élégante." },
  { q: "Pour quel accord le Sol à la basse peut-il être la fondamentale ?", opts: ["Accord de Do majeur uniquement", "Accord de Sol majeur (V), Sol mineur, Sol7, etc.", "Accord de Mi mineur", "Accord de Fa majeur"], a: 1, fb: "Sol à la basse peut être la fondamentale de V (Sol–Si–Ré), de Vm, de V7, etc. C'est pourquoi il faut analyser la tonalité et le contexte avant de décider de l'accord." },
  { q: "Quand une note de basse est Sol en Do majeur, quels accords sont possibles avec Sol comme fondamentale ?", opts: ["I, IV, II seulement", "V (Sol–Si–Ré) et VII (Sol–Si–Ré avec la couleur diminuée) principalement", "Seulement I6/4", "Seulement I à l'état fondamental"], a: 1, fb: "En Do majeur, Sol à la basse comme fondamentale donne principalement V (Sol–Si–Ré). Sol peut aussi être la quinte de I (Do–Mi–Sol) en 2e renversement, ou la tierce de Mi mineur." },

  // ── La sensible à la basse = V6 ──────────────────────────────────────────
  { q: "Si la basse est la sensible (7e degré) en Do majeur, quel accord est obligatoire ?", opts: ["VII diminué à l'état fondamental", "V6 (1er renversement de V)", "IV6", "I6"], a: 1, fb: "La sensible (Si en Do majeur) à la basse impose obligatoirement V6 — le 1er renversement de l'accord de dominante. La sensible ne peut pas être fondamentale à la basse dans le style strict." },
  { q: "Pourquoi la sensible à la basse donne-t-elle V6 et non VIIdim à l'état fondamental ?", opts: ["Pour éviter la quinte diminuée à la basse", "Parce que VIIdim à l'état fondamental crée une basse instable avec une quinte diminuée difficile à doubler et à résoudre", "Par convention arbitraire", "Parce que V6 est plus facile à jouer"], a: 1, fb: "VIIdim à l'état fondamental (Si–Ré–Fa) avec Si à la basse produit une quinte diminuée trop instable. Le style SATB strict impose V6 : la sensible (Si) est la tierce de Sol–Si–Ré, créant une harmonie de dominante naturelle." },
  { q: "En Sol majeur, la sensible est Fa#. Si Fa# est à la basse, l'accord est :", opts: ["VII à l'état fondamental", "V6 en Sol majeur", "II6", "IV6"], a: 1, fb: "En Sol majeur, la sensible est Fa#. Fa# à la basse = tierce de l'accord de Ré (V) = V6 en Sol majeur. La règle est absolue : sensible à la basse = V6." },
  { q: "En Ré mineur, la sensible est Do#. Si Do# est à la basse, l'accord est :", opts: ["VII diminué à l'état fondamental", "V6 en Ré mineur (harmonie mineure avec sensible rehaussée)", "IV en Ré mineur", "I6"], a: 1, fb: "En Ré mineur, la sensible harmonique est Do# (rehaussée). Do# à la basse = tierce de La–Do#–Mi (V) = V6 en Ré mineur. La règle est identique en mineur." },

  // ── Le 4e degré à la basse = IV ou II6 ───────────────────────────────────
  { q: "En Do majeur, Fa est le 4e degré. Quels accords sont possibles avec Fa à la basse ?", opts: ["I ou V uniquement", "IV à l'état fondamental (Fa–La–Do) ou II6 (Ré–Fa–La avec Fa à la basse)", "III6 ou VII seulement", "V7 ou I6/4"], a: 1, fb: "Fa à la basse en Do majeur peut être : la fondamentale de IV (Fa–La–Do à l'état fondamental) ou la tierce de II (Ré–Fa–La en 1er renversement = II6). Les deux sont courants selon le contexte harmonique." },
  { q: "Quelle est la différence d'effet entre IV à l'état fondamental et II6 quand Fa est à la basse ?", opts: ["Aucune différence", "IV est plus stable (basse à la fondamentale), II6 apporte une couleur plus mobile vers V", "II6 est plus stable", "IV se résout toujours sur I, II6 jamais"], a: 1, fb: "IV (Fa–La–Do) est stable à l'état fondamental. II6 (Ré–Fa–La) avec Fa à la basse est mobile — sa résolution naturelle vers V crée une progression SD→D plus dynamique." },
  { q: "Sur le 4e degré à la basse, quel choix est préférable si l'on veut préparer une cadence V–I ?", opts: ["IV à l'état fondamental", "II6 — car il oriente plus directement vers V", "I6/4 — pour renforcer la cadence", "VII6"], a: 1, fb: "II6 avec Fa à la basse se résout très naturellement sur V. Sa tierce (Ré) et sa fondamentale (dans les voix supérieures) préparent efficacement la dominante. C'est la progression II6–V–I, très fréquente." },

  // ── Règles du 6/4 de cadence ─────────────────────────────────────────────
  { q: "Sur quel type de temps le 6/4 de cadence peut-il apparaître ?", opts: ["Sur n'importe quel temps", "Uniquement sur un temps fort", "Uniquement sur un temps faible", "Sur la levée seulement"], a: 1, fb: "Le 6/4 de cadence (I6/4 = quinte de I à la basse) apparaît exclusivement sur un temps fort. Sa résolution vers V doit être immédiate, au temps suivant." },
  { q: "Après un 6/4 de cadence (I6/4 sur temps fort), quel accord DOIT suivre immédiatement ?", opts: ["I à l'état fondamental", "IV", "V (dominante)", "VI"], a: 2, fb: "Le 6/4 de cadence résout OBLIGATOIREMENT sur V. La séquence est : I6/4 (temps fort) → V → I. Sauter la résolution sur V ou aller vers un autre accord est une faute grave." },
  { q: "La progression correcte avec un 6/4 de cadence en Do majeur est :", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I est la progression cadentielle type. Le I6/4 apparaît sur le temps fort précédant la dominante. Il 'pèse' sur la quinte de la tonique et résout sur V." },
  { q: "Peut-on placer un 6/4 de cadence sur un temps faible ?", opts: ["Oui, c'est même recommandé", "Non — le 6/4 de cadence est réservé aux temps forts exclusivement", "Oui, mais uniquement en mineur", "Oui, si l'accord suivant est IV"], a: 1, fb: "Non — c'est une faute caractéristique de placer un 6/4 de cadence sur un temps faible. Le 6/4 de cadence exige obligatoirement le temps fort pour avoir son poids cadentiel et sa résolution correcte." },
  { q: "Que se passe-t-il si un 6/4 de cadence n'est pas suivi de V ?", opts: ["C'est acceptable en mineur", "C'est une faute grave de contrepoint — la résolution de V est obligatoire", "On peut aller directement vers I", "On peut aller vers IV"], a: 1, fb: "Ne pas résoudre I6/4 sur V est une faute grave. Le 6/4 crée une tension forte (quinte et quarte avec la basse) qui exige la résolution sur la dominante. La formule est invariablement I6/4 → V → I." },
  { q: "Quel accord la basse représente-t-elle dans un 6/4 de cadence en Do majeur ?", opts: ["Do (fondamentale de I)", "Mi (tierce de I)", "Sol (quinte de I)", "Fa (sous-dominante)"], a: 2, fb: "Dans I6/4 en Do majeur, la basse est Sol (quinte de Do–Mi–Sol). C'est cette quinte à la basse qui crée l'instabilité caractéristique du 6/4 et qui réclame la résolution vers V (qui a aussi Sol à la basse)." },

  // ── Choisir un accord compatible avec une note de soprano ─────────────────
  { q: "La note de soprano est Mi en Do majeur. Quels accords peuvent contenir Mi ?", opts: ["Seulement I (Do–Mi–Sol)", "I (Do–Mi–Sol), III (Mi–Sol–Si), VIm (La–Do–Mi)", "Seulement V (Sol–Si–Ré)", "Uniquement IV (Fa–La–Do)"], a: 1, fb: "Mi peut être : la tierce de I (Do–Mi–Sol), la fondamentale de III (Mi–Sol–Si), la quinte de VIm (La–Do–Mi). Le contexte harmonique détermine le meilleur choix." },
  { q: "La note de soprano est Sol en Do majeur. Quels accords peuvent la contenir ?", opts: ["I, III, V uniquement", "I (quinte), III (tierce), V (fondamentale), et aussi parfois VIm (aucune)", "I (quinte), V (fondamentale), et aussi les accords qui ont Sol comme fondamentale ou quinte dans la tonalité", "Uniquement V"], a: 2, fb: "Sol peut être : la quinte de I (Do–Mi–Sol), la fondamentale de V (Sol–Si–Ré), la tierce de Mi mineur (III). La liste complète dépend de la tonalité." },
  { q: "La note de soprano est Si en Do majeur. Quels accords sont compatibles ?", opts: ["Seulement V (Sol–Si–Ré)", "V (fondamentale Sol, tierce Si), I (accord de septième De–Mi–Sol–Si), VIIdim (Si–Ré–Fa)", "Seulement III", "I, IV, V, VIIdim"], a: 1, fb: "Si peut être : la tierce de V (Sol–Si–Ré), la 7te de I7 (Do–Mi–Sol–Si), ou la fondamentale de VIIdim (Si–Ré–Fa). V est le choix le plus courant en style SATB." },
  { q: "Quand on cherche les accords compatibles avec une note de soprano, quel critère est prioritaire ?", opts: ["L'accord qui sonne le mieux isolément", "La note de soprano doit être fondamentale, tierce, quinte ou (parfois) 7te de l'accord retenu — dans la tonalité", "L'accord le plus simple à réaliser", "L'accord qui a le plus de notes en commun avec le précédent"], a: 1, fb: "La note de soprano doit être une note constitutive de l'accord (fondamentale, tierce, quinte ou 7te dans le style SATB strict). La tonalité et la logique fonctionnelle orientent le choix final." },

  // ── Identifier les notes étrangères ─────────────────────────────────────
  { q: "Qu'est-ce qu'une note de passage ?", opts: ["Une note tenue d'une mesure à l'autre", "Une note étrangère à l'accord qui relie par mouvement conjoint deux notes harmoniques", "Une note broderie au-dessus ou en dessous d'une note réelle", "Une note anticipée avant le temps"], a: 1, fb: "La note de passage est une note non harmonique qui se glisse par mouvement conjoint entre deux notes harmoniques (par ex. Do–Ré–Mi où Ré est de passage). Elle doit être brève et non accentuée." },
  { q: "Qu'est-ce qu'une broderie ?", opts: ["Un ornement mélodique autour d'une note réelle, revenant à la même note", "Une note de passage entre deux harmonies différentes", "Un retard de résolution d'une dissonance", "Une anticipation de la note suivante"], a: 0, fb: "La broderie tourne autour d'une note réelle : note réelle → note adjacente (demi-ton ou ton) → retour à la note réelle. Ex. Mi–Fa–Mi ou Mi–Ré#–Mi. La note centrale est la note réelle de l'accord." },
  { q: "Qu'est-ce qu'un retard ?", opts: ["Une note arrivant avant son accord", "Une note harmonique prolongée au-delà du changement d'accord, créant une dissonance résolue par mouvement descendant", "Une note de passage non accentuée", "Une broderie à distance de tierce"], a: 1, fb: "Le retard est une note tenue depuis l'accord précédent qui se prolonge dans le nouvel accord, créant une dissonance. Elle résout obligatoirement par mouvement conjoint descendant. Ex. : 4–3, 7–6, 9–8." },
  { q: "Qu'est-ce qu'une anticipation ?", opts: ["Une note qui arrive en avance sur son accord harmonique", "Un retard résolu vers le haut", "Une note de passage sur temps fort", "Une note broderie chromatique"], a: 0, fb: "L'anticipation est une note qui appartient à l'accord suivant mais arrive avant le changement d'accord. Elle est généralement brève, non accentuée, et souvent sur une levée ou un temps faible." },
  { q: "Pourquoi doit-on identifier les notes étrangères avant d'harmoniser un soprano ?", opts: ["Pour les supprimer de la mélodie", "Pour ne pas créer de faux accords sur des notes non réelles — harmoniser uniquement les notes structurelles", "Pour les doubler au ténor", "Pour les transposer à l'octave"], a: 1, fb: "Harmoniser une note de passage ou une broderie comme si elle était harmonique crée un accord incorrect. On doit d'abord identifier les notes étrangères, puis harmoniser uniquement les notes réelles de la mélodie." },
  { q: "Dans le soprano Sol–Fa–Mi (2 temps sur Sol, Fa très bref, Mi), Fa est probablement :", opts: ["Une note harmonique réelle à harmoniser", "Une note de passage entre Sol et Mi — ne pas créer un accord sur Fa", "Un retard de Sol", "Une anticipation de Mi"], a: 1, fb: "Fa bref entre Sol et Mi, par mouvement conjoint descendant, est typiquement une note de passage. Il ne faut pas changer d'accord sur Fa — on maintient l'harmonie de Sol puis on change sur Mi." },

  // ── Harmonisation en Do majeur ────────────────────────────────────────────
  { q: "En Do majeur, la basse est Do–Si–La–Fa–Sol–Do. Quelle harmonisation correspond à I–V6–VI–IV–V–I ?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "Do = I (fondamentale), Si = V6 (Si = tierce de V à la basse = 1er renversement), La = VI, Fa = IV, Sol = V, Do = I. Progression classique T–D–T–SD–D–T." },
  { q: "En Do majeur, quelle est la basse naturelle pour le VI (La mineur) ?", opts: ["Do", "Mi", "La", "Sol"], a: 2, fb: "La est la fondamentale de VI (La–Do–Mi) en Do majeur. La à la basse = VI à l'état fondamental. C'est l'accord de relatif mineur, très utilisé après I ou V." },
  { q: "En Do majeur, la basse Do–Mi–Sol–Mi–Do correspond à :", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "Do = I (fondamentale), Mi = I6 (tierce de Do–Mi–Sol à la basse = 1er renversement), Sol = I6/4 (quinte = 2e renversement), Mi = I6, Do = I. On reste sur l'accord de Do avec différentes positions — arpège harmonique." },
  { q: "La cadence parfaite en Do majeur est :", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "La cadence parfaite = V → I. En Do majeur : Sol–Si–Ré → Do–Mi–Sol. Les deux accords doivent être à l'état fondamental pour que la cadence soit 'parfaite' au sens strict." },

  // ── Harmonisation en Sol majeur ───────────────────────────────────────────
  { q: "En Sol majeur, la sensible est :", opts: ["Fa naturel", "Fa#", "Do", "Mi"], a: 1, fb: "En Sol majeur, la gamme est Sol–La–Si–Do–Ré–Mi–Fa#–Sol. La sensible (7e degré) est Fa#. À la basse, Fa# impose V6 (Ré–Fa#–La avec Fa# à la basse)." },
  { q: "En Sol majeur, V6 à la basse correspond à :", opts: ["Sol à la basse", "Fa# à la basse (tierce de l'accord de Ré = V)", "Mi à la basse", "Si à la basse"], a: 1, fb: "En Sol majeur, V = Ré–Fa#–La. Fa# est la tierce de cet accord. Fa# à la basse = V6 (1er renversement de la dominante de Sol majeur)." },
  { q: "En Sol majeur, la progression I–V–VI–IV–V–I avec basse Sol–Ré–Mi–Do–Ré–Sol est :", opts: ["Incorrecte — Ré à la basse n'est pas V", "Correcte — Ré est la fondamentale de V (Ré–Fa#–La)", "Correcte mais V devrait être en 1er renversement", "Incorrecte — Mi ne correspond pas à VI"], a: 1, fb: "Sol = I (fondamentale), Ré = V (fondamentale), Mi = VI (Mi–Sol–Si = VIm), Do = IV (Do–Mi–Sol), Ré = V, Sol = I. Progression T–D–T–SD–D–T, entièrement correcte." },
  { q: "En Sol majeur, l'accord IV est :", opts: ["Do–Mi–Sol (Do majeur)", "Ré–Fa#–La", "Mi–Sol–Si", "La–Do–Mi"], a: 0, fb: "IV en Sol majeur = Do–Mi–Sol (Do majeur). Construit sur le 4e degré Sol majeur (Sol–La–Si–Do), l'accord diatonique est Do–Mi–Sol. C'est la sous-dominante de Sol." },

  // ── Harmonisation en Ré mineur ────────────────────────────────────────────
  { q: "En Ré mineur harmonique, la sensible est :", opts: ["Do naturel", "Do#", "Si bémol", "La"], a: 1, fb: "En Ré mineur harmonique, la 7te est rehaussée : Do naturel → Do#. Do# est la sensible qui monte sur Ré (tonique). À la basse, Do# impose V6 (La–Do#–Mi avec Do# à la basse)." },
  { q: "En Ré mineur, Si bémol à la basse peut correspondre à :", opts: ["IV seulement", "bVI (Si bémol–Ré–Fa = bVI à l'état fondamental) ou IV6 (Sol–Si b–Ré avec Si b à la basse)", "I seulement", "V6"], a: 1, fb: "Sib à la basse en Ré mineur peut être la fondamentale de bVI (Sib–Ré–Fa, 6e degré bémolisé) ou la tierce de IV (Sol–Sib–Ré en 1er renversement). Les deux sont possibles selon le contexte." },
  { q: "En Ré mineur, quelle est la basse pour le V à l'état fondamental ?", opts: ["Ré", "La", "Do#", "Sol"], a: 1, fb: "V en Ré mineur = La–Do#–Mi (dominante harmonique). La est la fondamentale = La à la basse = V à l'état fondamental. La résolution La→Ré est la cadence parfaite en Ré mineur." },
  { q: "En Ré mineur, la progression Im–V–bVI–IV–V–Im correspond à la basse :", opts: ["Ré–La–Sol–Sib–La–Ré", "Ré–La–Sib–Sol–La–Ré", "La–Ré–Sib–Sol–La–Ré", "Ré–La–Sib–Do#–La–Ré"], a: 1, fb: "Im=Ré, V=La, bVI=Sib (fondamentale de Sib–Ré–Fa), IV=Sol (fondamentale de Sol–Sib–Ré en Ré mineur), V=La, Im=Ré. Basse : Ré–La–Sib–Sol–La–Ré." },

  // ── Choisir entre plusieurs accords possibles ─────────────────────────────
  { q: "Sur une même note de basse, il existe souvent 2–3 accords possibles. Quel critère permet de choisir ?", opts: ["Toujours le même accord indépendamment du contexte", "La logique fonctionnelle (T→SD→D→T), la mélodie au soprano, et l'évitement des parallélismes", "L'accord avec le moins de notes altérées", "L'accord le plus aigu"], a: 1, fb: "Le choix entre plusieurs accords possibles dépend de la logique fonctionnelle (enchaînement T→SD→D→T), de la compatibilité avec le soprano, et de l'évitement des quintes et octaves parallèles." },
  { q: "La note Ré à la basse en Do majeur peut être : la fondamentale de II (Ré–Fa–La) ou la quinte de V (Sol–Si–Ré). Quel critère décide ?", opts: ["Toujours II car c'est la fondamentale", "La position dans la phrase : II avant V (SD→D), V6/4 rarement utilisé ; le soprano et le contexte cadentiel décident", "Toujours V6/4", "On choisit au hasard"], a: 1, fb: "Si Ré à la basse précède Sol ou Mi, II (Ré–Fa–La) est naturel comme sous-dominante. Si on est en fin de phrase cadentielle avec Sol au soprano, V6/4 peut convenir. Le contexte décide." },
  { q: "Sur La à la basse en Do majeur, quels sont les accords les plus courants ?", opts: ["VIm (La–Do–Mi) ou IV6 (Fa–La–Do avec La à la basse)", "I ou V uniquement", "III ou VII", "V ou II"], a: 0, fb: "La à la basse peut être la fondamentale de VIm (La–Do–Mi, 6e degré) ou la tierce de IV (Fa–La–Do en 1er renversement = IV6). Le contexte harmonique et la mélodie soprano guident le choix." },

  // ── Rythme harmonique ─────────────────────────────────────────────────────
  { q: "Qu'est-ce que le rythme harmonique ?", opts: ["La vitesse à laquelle le batteur joue", "La fréquence à laquelle les accords changent dans une progression", "Le nombre de voix dans l'accord", "La durée de chaque note au soprano"], a: 1, fb: "Le rythme harmonique = fréquence des changements d'accords. Rapide = un accord par temps ou note ; lent = un accord par mesure ou plusieurs mesures. Il doit être adapté au tempo et au style." },
  { q: "Dans un style SATB strict, doit-on changer d'accord sur chaque note rapide du soprano ?", opts: ["Oui, chaque note doit avoir son accord", "Non — les notes rapides (croches en 4/4 lent) sont souvent des notes de passage ou broderies ; on change d'accord sur les notes longues/accentuées", "Oui, mais seulement au soprano", "Non, jamais sur deux notes consécutives"], a: 1, fb: "Changer d'accord sur chaque note rapide est une faute typique. Les notes brèves sont souvent des notes étrangères. Le rythme harmonique suit la pulsation structurelle de la pièce — généralement la noire ou la blanche." },
  { q: "Quel est le signe qu'on harmonise trop vite (rythme harmonique trop dense) ?", opts: ["Des accords trop stables", "Des fautes de quintes ou d'octaves parallèles fréquentes et des changements d'accord sur des notes non harmoniques", "Un soprano trop aigu", "Trop de renversements"], a: 1, fb: "Un rythme harmonique trop dense entraîne des changements d'accord sur des notes étrangères, ce qui génère des dissonances et des parallélismes. La solution : identifier les notes réelles et harmoniser à une fréquence plus lente." },
  { q: "En 4/4, quel est un rythme harmonique courant pour une harmonisation DEM de niveau moyen ?", opts: ["Un accord toutes les 2 mesures", "Un accord par mesure ou un accord tous les deux temps (demi-mesure)", "Un accord par note (croche)", "Quatre accords différents par mesure"], a: 1, fb: "En 4/4, le rythme harmonique standard est un accord par mesure ou tous les deux temps. Ce rythme laisse le temps aux notes étrangères de s'exprimer sans provoquer de sur-harmonisation." },

  // ── Progressions T→SD→D→T ─────────────────────────────────────────────────
  { q: "Que signifie la progression T→SD→D→T en harmonisation ?", opts: ["Tonique vers sous-dominante vers dominante vers tonique — le cycle harmonique fondamental", "Tenuto, staccato, détaché, tenuto", "Tréble, soprano, basse, ténor", "Tierce, sixte, demi-ton, ton"], a: 0, fb: "T=Tonique (I, VI), SD=Sous-Dominante (IV, II), D=Dominante (V, VIIdim). La progression naturelle T→SD→D→T crée tension et résolution. En Do majeur : I–IV–V–I." },
  { q: "Quel est l'exemple type de la progression T→SD→D→T en Do majeur ?", opts: ["I–V–IV–I", "I–II6–V–I ou I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I ou I–II6–V–I sont les progressions T→SD→D→T par excellence. La sous-dominante (IV ou II) précède la dominante (V) qui résout sur la tonique (I)." },
  { q: "La progression IV–V–IV en harmonisation est :", opts: ["Excellente — elle alterne SD et D", "À éviter — retour en arrière de V vers IV (D→SD) contre le flux T→SD→D→T", "Neutre — ni bonne ni mauvaise", "Obligatoire avant toute cadence"], a: 1, fb: "IV–V–IV est une faute de progression : on recule de D (V) vers SD (IV), ce qui contredit le flux naturel. La progression doit avancer : SD→D→T. Revenir en arrière affaiblit la logique tonale." },
  { q: "VI est généralement classé comme :", opts: ["Dominante", "Tonique (substitut de I)", "Sous-dominante", "Accord de passage"], a: 1, fb: "VI (La–Do–Mi en Do majeur) est le relatif mineur de I — il partage deux notes avec I. Il fonctionne comme substitut de la Tonique et peut remplacer I après une cadence évitée (V→VI au lieu de V→I)." },
  { q: "II est généralement classé comme :", opts: ["Tonique", "Sous-dominante (partage deux notes avec IV)", "Dominante", "Neutre"], a: 1, fb: "II (Ré–Fa–La en Do majeur) est la sous-dominante — il partage Fa et La avec IV (Fa–La–Do). II6 est très fréquent en harmonisation avant V, créant la progression SD→D." },
  { q: "La cadence évitée (cadence interrompue) se produit quand :", opts: ["V résout sur I comme prévu", "V résout sur VI au lieu de I — surprise harmonique", "IV résout sur V", "II va sur I directement"], a: 1, fb: "La cadence évitée = V→VI. Au lieu de résoudre sur I, la dominante se dirige vers VI (relatif mineur). C'est une surprise qui prolonge la phrase et crée de l'intérêt. La résolution finale sur I est reportée." },
  { q: "Dans une harmonisation de basse donnée, comment aborder la fin de phrase ?", opts: ["Finir sur n'importe quel accord", "Prévoir une cadence claire (V–I ou IV–V–I) avec les accords dans le bon ordre fonctionnel T→SD→D→T", "Finir toujours sur VI pour la variété", "Ne pas utiliser V avant I"], a: 1, fb: "La fin de phrase doit être planifiée : identifier la cadence (V–I pour cadence parfaite, IV–I pour cadence plagale, V6/4–V–I pour cadence avec 6/4), puis s'assurer que la progression y mène logiquement." },
  { q: "Quelle règle fondamentale guide l'enchaînement des accords en harmonisation ?", opts: ["Chaque accord peut suivre n'importe quel autre", "T peut aller vers SD ou D ; SD va vers D ou T ; D va vers T (ou VI en cadence évitée)", "Toujours alterner SD et D", "Les accords en renversement ne peuvent pas se suivre"], a: 1, fb: "La règle des fonctions harmoniques : T→SD, T→D, SD→D, D→T, D→VI (cadence évitée). Le retour SD→T est la cadence plagale. SD→SD et D→D sont possibles mais avec modération." },
  { q: "Pourquoi évite-t-on la progression V–IV en style SATB strict ?", opts: ["Elle est trop simple", "Elle représente un recul de D vers SD — contre le flux harmonique naturel ; la sensible (dans V) cherche à monter, pas à descendre vers IV", "Elle crée des quintes augmentées", "Elle n'existe pas en Do majeur"], a: 1, fb: "V→IV est un recul (D→SD). La sensible (Si en Do majeur) dans l'accord de V veut monter vers Do (I) — elle ne résout pas naturellement en IV. Cette progression affaiblit le sentiment tonal et est évitée en style strict." },
  { q: "Quelle progression est correcte entre deux accords de tonique ?", opts: ["I – I (répétition interdite)", "I – VI – I ou I – I6 – I (légitimes avec même fondamentale)", "I ne peut jamais être suivi d'un autre accord de tonique", "I doit toujours aller vers IV ou V"], a: 1, fb: "On peut passer de I à VI (substitut de tonique) ou de I à I6 (renversement pour mouvement de basse). La répétition à l'identique I–I est stérile mais pas une faute. L'important est la progression globale." },
  { q: "En harmonisation, qu'est-ce qu'une 'doublure' et quelle règle s'applique à l'état fondamental ?", opts: ["Jouer deux instruments — doubler tout accord possible", "Répéter une note de l'accord dans une autre voix — à l'état fondamental, doubler la fondamentale de préférence", "Ajouter une 7te à l'accord", "Répéter l'accord deux mesures de suite"], a: 1, fb: "La doublure = écrire la même hauteur dans deux voix différentes (à l'octave ou unisson). À l'état fondamental, on double de préférence la fondamentale. On évite de doubler la sensible (qui doit monter) et la tierce (couleur de l'accord)." },
];

const questionsEn: Question[] = [
  { q: "A bass note is the root of the chord. In what position is this chord?", opts: ["First inversion", "Second inversion", "Root position", "Third inversion"], a: 2, fb: "When the bass is the root of the chord, the chord is in root position (base position). This is the most stable position, preferred on strong beats and at cadences." },
  { q: "If the bass note is the third of a chord, which inversion is it?", opts: ["Root position", "First inversion (sixth chord)", "Second inversion (6/4)", "Fifth position"], a: 1, fb: "Third in the bass = first inversion, notated as 'sixth chord' (figured bass: 6). For example, C–E–G with E in the bass gives a C chord in first inversion." },
  { q: "If the bass note is the fifth of a chord, which inversion is it?", opts: ["Root position", "First inversion", "Second inversion (fourth and sixth chord)", "Open position"], a: 2, fb: "Fifth in the bass = second inversion, notated '6/4' (figured bass: 6 and 4). This is the most unstable inversion — it requires careful resolution, especially as a cadential 6/4." },
  { q: "The chord C–E–G with G in the bass corresponds to:", opts: ["I in root position", "I in first inversion", "I in second inversion", "V6"], a: 2, fb: "G is the fifth of the C major chord. G in the bass = second inversion = I6/4 (C 6/4). This chord is highly unstable and appears mainly as a cadential 6/4." },
  { q: "The chord G–B–D with B in the bass is:", opts: ["V in root position", "V6 (first inversion of V)", "V6/4 (second inversion)", "VII in root position"], a: 1, fb: "B is the third of the G major chord. B in the bass = first inversion of V = V6. This inversion is very common and produces an elegant stepwise bass." },
  { q: "For which chord can G in the bass be the root?", opts: ["C major chord only", "G major chord (V), G minor, G7, etc.", "E minor chord", "F major chord"], a: 1, fb: "G in the bass can be the root of V (G–B–D), Gm, G7, etc. That is why you must analyze the key and context before deciding on the chord." },
  { q: "When the bass note is G in C major, what chords are possible with G as the root?", opts: ["I, IV, II only", "V (G–B–D) and VII (with diminished color) primarily", "Only I6/4", "Only I in root position"], a: 1, fb: "In C major, G in the bass as root primarily gives V (G–B–D). G can also be the fifth of I (C–E–G) in second inversion, or the third of E minor." },
  { q: "If the bass is the leading tone (7th degree) in C major, which chord is mandatory?", opts: ["Diminished VII in root position", "V6 (first inversion of V)", "IV6", "I6"], a: 1, fb: "The leading tone (B in C major) in the bass mandates V6 — the first inversion of the dominant chord. The leading tone cannot be the root in the bass in strict style." },
  { q: "Why does the leading tone in the bass give V6 and not VIIdim in root position?", opts: ["To avoid a diminished fifth in the bass", "Because VIIdim in root position creates an unstable bass with a diminished fifth that is hard to double and resolve", "An arbitrary convention", "Because V6 is easier to play"], a: 1, fb: "VIIdim in root position (B–D–F) with B in the bass produces an overly unstable diminished fifth. Strict SATB style mandates V6: the leading tone (B) is the third of G–B–D, creating a natural dominant harmony." },
  { q: "In G major, the leading tone is F#. If F# is in the bass, the chord is:", opts: ["VII in root position", "V6 in G major", "II6", "IV6"], a: 1, fb: "In G major, the leading tone is F#. F# in the bass = third of the D chord (V) = V6 in G major. The rule is absolute: leading tone in the bass = V6." },
  { q: "In D minor, the leading tone is C#. If C# is in the bass, the chord is:", opts: ["Diminished VII in root position", "V6 in D minor (harmonic minor with raised leading tone)", "IV in D minor", "I6"], a: 1, fb: "In D minor, the harmonic leading tone is C# (raised). C# in the bass = third of A–C#–E (V) = V6 in D minor. The rule is identical in minor." },
  { q: "In C major, F is the 4th degree. What chords are possible with F in the bass?", opts: ["I or V only", "IV in root position (F–A–C) or II6 (D–F–A with F in the bass)", "III6 or VII only", "V7 or I6/4"], a: 1, fb: "F in the bass in C major can be: the root of IV (F–A–C in root position) or the third of II (D–F–A in first inversion = II6). Both are common depending on the harmonic context." },
  { q: "What is the difference in effect between IV in root position and II6 when F is in the bass?", opts: ["No difference", "IV is more stable (root in bass), II6 brings a more mobile color toward V", "II6 is more stable", "IV always resolves to I, II6 never does"], a: 1, fb: "IV (F–A–C) is stable in root position. II6 (D–F–A) with F in the bass is mobile — its natural resolution toward V creates a more dynamic SD→D progression." },
  { q: "Over the 4th degree in the bass, which choice is preferable to prepare a V–I cadence?", opts: ["IV in root position", "II6 — because it points more directly toward V", "I6/4 — to reinforce the cadence", "VII6"], a: 1, fb: "II6 with F in the bass resolves very naturally to V. Its third (D) and its root (in the upper voices) effectively prepare the dominant. This is the progression II6–V–I, very frequent." },
  { q: "On what type of beat can the cadential 6/4 appear?", opts: ["On any beat", "Only on a strong beat", "Only on a weak beat", "Only on an upbeat"], a: 1, fb: "The cadential 6/4 (I6/4 = fifth of I in the bass) appears exclusively on a strong beat. Its resolution to V must be immediate, on the following beat." },
  { q: "After a cadential 6/4 (I6/4 on a strong beat), which chord MUST follow immediately?", opts: ["I in root position", "IV", "V (dominant)", "VI"], a: 2, fb: "The cadential 6/4 resolves OBLIGATORILY to V. The sequence is: I6/4 (strong beat) → V → I. Skipping the resolution to V or going to another chord is a serious error." },
  { q: "The correct progression with a cadential 6/4 in C major is:", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I is the typical cadential progression. The I6/4 appears on the strong beat preceding the dominant. It 'weighs' on the fifth of the tonic and resolves to V." },
  { q: "Can a cadential 6/4 be placed on a weak beat?", opts: ["Yes, it is even recommended", "No — the cadential 6/4 is reserved for strong beats exclusively", "Yes, but only in minor", "Yes, if the following chord is IV"], a: 1, fb: "No — it is a characteristic error to place a cadential 6/4 on a weak beat. The cadential 6/4 requires the strong beat to carry its cadential weight and correct resolution." },
  { q: "What happens if a cadential 6/4 is not followed by V?", opts: ["It is acceptable in minor", "It is a serious counterpoint error — the resolution to V is mandatory", "You can go directly to I", "You can go to IV"], a: 1, fb: "Not resolving I6/4 to V is a serious error. The 6/4 creates strong tension (fifth and fourth against the bass) that demands resolution to the dominant. The formula is invariably I6/4 → V → I." },
  { q: "What chord does the bass represent in a cadential 6/4 in C major?", opts: ["C (root of I)", "E (third of I)", "G (fifth of I)", "F (subdominant)"], a: 2, fb: "In I6/4 in C major, the bass is G (fifth of C–E–G). It is this fifth in the bass that creates the characteristic instability of the 6/4 and calls for resolution to V (which also has G in the bass)." },
  { q: "The soprano note is E in C major. What chords can contain E?", opts: ["Only I (C–E–G)", "I (C–E–G), III (E–G–B), VIm (A–C–E)", "Only V (G–B–D)", "Only IV (F–A–C)"], a: 1, fb: "E can be: the third of I (C–E–G), the root of III (E–G–B), the fifth of VIm (A–C–E). The harmonic context determines the best choice." },
  { q: "The soprano note is G in C major. What chords can contain it?", opts: ["I, III, V only", "I (fifth), III (third), V (root), and sometimes VIm", "I (fifth), V (root), and also chords that have G as root or fifth in the key", "Only V"], a: 2, fb: "G can be: the fifth of I (C–E–G), the root of V (G–B–D), the third of E minor (III). The complete list depends on the key." },
  { q: "The soprano note is B in C major. What chords are compatible?", opts: ["Only V (G–B–D)", "V (root G, third B), I (seventh chord C–E–G–B), VIIdim (B–D–F)", "Only III", "I, IV, V, VIIdim"], a: 1, fb: "B can be: the third of V (G–B–D), the 7th of I7 (C–E–G–B), or the root of VIIdim (B–D–F). V is the most common choice in SATB style." },
  { q: "When looking for chords compatible with a soprano note, what criterion is most important?", opts: ["The chord that sounds best in isolation", "The soprano note must be the root, third, fifth, or (sometimes) seventh of the chosen chord — within the key", "The simplest chord to realize", "The chord with the most notes in common with the previous one"], a: 1, fb: "The soprano note must be a constituent note of the chord (root, third, fifth, or seventh in strict SATB style). The key and functional logic guide the final choice." },
  { q: "What is a passing note?", opts: ["A note held from one measure to the next", "A non-harmonic note that connects two harmonic notes by stepwise motion", "A neighbor note above or below a real note", "A note anticipated before the beat"], a: 1, fb: "A passing note is a non-harmonic note that slips by stepwise motion between two harmonic notes (e.g., C–D–E where D is passing). It must be brief and unaccented." },
  { q: "What is a neighbor note (ornamental note)?", opts: ["An ornamental figure around a real note, returning to the same note", "A passing note between two different harmonies", "A delayed resolution of a dissonance", "An anticipation of the next note"], a: 0, fb: "The neighbor note circles around a real note: real note → adjacent note (half step or whole step) → return to the real note. E.g. E–F–E or E–D#–E. The central note is the real harmonic note." },
  { q: "What is a suspension?", opts: ["A note arriving before its chord", "A harmonic note prolonged beyond a chord change, creating a dissonance resolved by stepwise descending motion", "An unaccented passing note", "A neighbor note at the interval of a third"], a: 1, fb: "A suspension is a note held from the previous chord that extends into the new chord, creating a dissonance. It resolves obligatorily by stepwise descending motion. E.g.: 4–3, 7–6, 9–8." },
  { q: "What is an anticipation?", opts: ["A note that arrives early belonging to the next chord", "A suspension resolved upward", "A passing note on a strong beat", "A chromatic neighbor note"], a: 0, fb: "An anticipation is a note that belongs to the next chord but arrives before the chord change. It is generally brief, unaccented, and often on an upbeat or weak beat." },
  { q: "Why must you identify non-harmonic notes before harmonizing a soprano?", opts: ["To remove them from the melody", "To avoid creating wrong chords on non-real notes — harmonize only the structural notes", "To double them in the tenor", "To transpose them up an octave"], a: 1, fb: "Harmonizing a passing note or neighbor note as if it were harmonic creates an incorrect chord. You must first identify non-harmonic notes, then harmonize only the real melodic notes." },
  { q: "In the soprano G–F–E (2 beats on G, F very brief, E), F is probably:", opts: ["A real harmonic note to be harmonized", "A passing note between G and E — do not create a chord on F", "A suspension of G", "An anticipation of E"], a: 1, fb: "F brief between G and E, by stepwise descending motion, is typically a passing note. Do not change the chord on F — maintain the G harmony, then change on E." },
  { q: "In C major, the bass is C–B–A–F–G–C. What harmonization corresponds to I–V6–VI–IV–V–I?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "C = I (root), B = V6 (B = third of V in the bass = first inversion), A = VI, F = IV, G = V, C = I. Classic progression T–D–T–SD–D–T." },
  { q: "In C major, what is the natural bass for VI (A minor)?", opts: ["C", "E", "A", "G"], a: 2, fb: "A is the root of VI (A–C–E) in C major. A in the bass = VI in root position. This is the relative minor chord, very commonly used after I or V." },
  { q: "In C major, the bass C–E–G–E–C corresponds to:", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "C = I (root), E = I6 (first inversion), G = I6/4 (second inversion), E = I6, C = I. We stay on the C chord with different positions — harmonic arpeggio." },
  { q: "The perfect cadence in C major is:", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "The perfect cadence = V → I. In C major: G–B–D → C–E–G. Both chords must be in root position for the cadence to be 'perfect' in the strict sense." },
  { q: "In G major, the leading tone is:", opts: ["F natural", "F#", "C", "E"], a: 1, fb: "In G major, the scale is G–A–B–C–D–E–F#–G. The leading tone (7th degree) is F#. In the bass, F# mandates V6 (D–F#–A with F# in the bass)." },
  { q: "In G major, V6 in the bass corresponds to:", opts: ["G in the bass", "F# in the bass (third of the D chord = V)", "E in the bass", "B in the bass"], a: 1, fb: "In G major, V = D–F#–A. F# is the third of this chord. F# in the bass = V6 (first inversion of the dominant of G major)." },
  { q: "In G major, the progression I–V–VI–IV–V–I with bass G–D–E–C–D–G is:", opts: ["Incorrect — D in the bass is not V", "Correct — D is the root of V (D–F#–A)", "Correct but V should be in first inversion", "Incorrect — E does not correspond to VI"], a: 1, fb: "G = I (root), D = V (root), E = VI (E–G–B = VIm), C = IV (C–E–G), D = V, G = I. Progression T–D–T–SD–D–T, entirely correct." },
  { q: "In G major, the IV chord is:", opts: ["C–E–G (C major)", "D–F#–A", "E–G–B", "A–C–E"], a: 0, fb: "IV in G major = C–E–G (C major). Built on the 4th degree of G major (G–A–B–C), the diatonic chord is C–E–G. This is the subdominant of G." },
  { q: "In D harmonic minor, the leading tone is:", opts: ["C natural", "C#", "Bb", "A"], a: 1, fb: "In D harmonic minor, the 7th is raised: C natural → C#. C# is the leading tone that rises to D (tonic). In the bass, C# mandates V6 (A–C#–E with C# in the bass)." },
  { q: "In D minor, Bb in the bass can correspond to:", opts: ["IV only", "bVI (Bb–D–F = bVI in root position) or IV6 (G–Bb–D with Bb in the bass)", "I only", "V6"], a: 1, fb: "Bb in the bass in D minor can be the root of bVI (Bb–D–F, flatted 6th degree) or the third of IV (G–Bb–D in first inversion). Both are possible depending on context." },
  { q: "In D minor, what is the bass for V in root position?", opts: ["D", "A", "C#", "G"], a: 1, fb: "V in D minor = A–C#–E (harmonic dominant). A is the root = A in the bass = V in root position. The resolution A→D is the perfect cadence in D minor." },
  { q: "In D minor, the progression Im–V–bVI–IV–V–Im corresponds to the bass:", opts: ["D–A–G–Bb–A–D", "D–A–Bb–G–A–D", "A–D–Bb–G–A–D", "D–A–Bb–C#–A–D"], a: 1, fb: "Im=D, V=A, bVI=Bb (root of Bb–D–F), IV=G (root of G–Bb–D in D minor), V=A, Im=D. Bass: D–A–Bb–G–A–D." },
  { q: "Over the same bass note, there are often 2–3 possible chords. What criterion allows you to choose?", opts: ["Always the same chord regardless of context", "Functional logic (T→SD→D→T), the soprano melody, and avoidance of parallel motion", "The chord with the fewest altered notes", "The highest-pitched chord"], a: 1, fb: "Choosing between multiple possible chords depends on functional logic (T→SD→D→T progression), compatibility with the soprano, and avoidance of parallel fifths and octaves." },
  { q: "The note D in the bass in C major can be: the root of II (D–F–A) or the fifth of V (G–B–D). What criterion decides?", opts: ["Always II because it is the root", "Position in the phrase: II before V (SD→D), V6/4 rarely used; soprano and cadential context decide", "Always V6/4", "You choose randomly"], a: 1, fb: "If D in the bass precedes G or E, II (D–F–A) is natural as subdominant. If we are at the end of a cadential phrase with G in the soprano, V6/4 may fit. Context decides." },
  { q: "Over A in the bass in C major, what are the most common chords?", opts: ["VIm (A–C–E) or IV6 (F–A–C with A in the bass)", "I or V only", "III or VII", "V or II"], a: 0, fb: "A in the bass can be the root of VIm (A–C–E, 6th degree) or the third of IV (F–A–C in first inversion = IV6). The harmonic context and soprano melody guide the choice." },
  { q: "What is harmonic rhythm?", opts: ["The speed at which the drummer plays", "The frequency at which chords change in a progression", "The number of voices in the chord", "The duration of each soprano note"], a: 1, fb: "Harmonic rhythm = frequency of chord changes. Fast = one chord per beat or note; slow = one chord per measure or several measures. It must be adapted to the tempo and style." },
  { q: "In strict SATB style, should you change chord on every fast soprano note?", opts: ["Yes, each note must have its chord", "No — fast notes are often passing or neighbor notes; change chords on long/accented notes", "Yes, but only in the soprano", "No, never on two consecutive notes"], a: 1, fb: "Changing chord on every fast note is a typical error. Brief notes are often non-harmonic. Harmonic rhythm follows the structural pulse of the piece — generally the quarter note or half note." },
  { q: "What is the sign that you are harmonizing too quickly (harmonic rhythm too dense)?", opts: ["Chords that are too stable", "Frequent parallel fifth or octave errors and chord changes on non-harmonic notes", "A soprano that is too high", "Too many inversions"], a: 1, fb: "Too dense a harmonic rhythm leads to chord changes on non-harmonic notes, generating dissonances and parallel motion. The solution: identify the real notes and harmonize at a slower frequency." },
  { q: "In 4/4, what is a common harmonic rhythm for an intermediate-level harmonization exercise?", opts: ["One chord every 2 measures", "One chord per measure or one chord every two beats (half measure)", "One chord per note (eighth note)", "Four different chords per measure"], a: 1, fb: "In 4/4, the standard harmonic rhythm is one chord per measure or every two beats. This pace leaves room for non-harmonic notes to breathe without over-harmonizing." },
  { q: "What does the T→SD→D→T progression mean in harmonization?", opts: ["Tonic toward subdominant toward dominant toward tonic — the fundamental harmonic cycle", "Tenuto, staccato, detached, tenuto", "Treble, soprano, bass, tenor", "Third, sixth, half step, whole step"], a: 0, fb: "T=Tonic (I, VI), SD=Subdominant (IV, II), D=Dominant (V, VIIdim). The natural progression T→SD→D→T creates tension and resolution. In C major: I–IV–V–I." },
  { q: "What is the typical example of T→SD→D→T progression in C major?", opts: ["I–V–IV–I", "I–II6–V–I or I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I or I–II6–V–I are the T→SD→D→T progressions par excellence. The subdominant (IV or II) precedes the dominant (V), which resolves to the tonic (I)." },
  { q: "The progression IV–V–IV in harmonization is:", opts: ["Excellent — it alternates SD and D", "To be avoided — backward motion from V to IV (D→SD) goes against the T→SD→D→T flow", "Neutral — neither good nor bad", "Mandatory before any cadence"], a: 1, fb: "IV–V–IV is a progression error: you move backward from D (V) to SD (IV), contradicting the natural flow. The progression must move forward: SD→D→T. Moving backward weakens the tonal logic." },
  { q: "VI is generally classified as:", opts: ["Dominant", "Tonic (substitute for I)", "Subdominant", "Passing chord"], a: 1, fb: "VI (A–C–E in C major) is the relative minor of I — it shares two notes with I. It functions as a Tonic substitute and can replace I after a deceptive cadence (V→VI instead of V→I)." },
  { q: "II is generally classified as:", opts: ["Tonic", "Subdominant (shares two notes with IV)", "Dominant", "Neutral"], a: 1, fb: "II (D–F–A in C major) is the subdominant — it shares F and A with IV (F–A–C). II6 is very common in harmonization before V, creating the SD→D progression." },
  { q: "The deceptive cadence occurs when:", opts: ["V resolves to I as expected", "V resolves to VI instead of I — harmonic surprise", "IV resolves to V", "II goes directly to I"], a: 1, fb: "Deceptive cadence = V→VI. Instead of resolving to I, the dominant moves to VI (relative minor). This is a surprise that extends the phrase and creates interest. The final resolution to I is deferred." },
  { q: "In a bass-given harmonization, how should you approach the end of a phrase?", opts: ["End on any chord", "Plan a clear cadence (V–I or IV–V–I) with chords in the correct functional order T→SD→D→T", "Always end on VI for variety", "Never use V before I"], a: 1, fb: "The end of a phrase must be planned: identify the cadence (V–I for perfect cadence, IV–I for plagal cadence, V6/4–V–I for cadence with 6/4), then ensure the progression leads to it logically." },
  { q: "What fundamental rule guides chord progressions in harmonization?", opts: ["Any chord can follow any other", "T can go to SD or D; SD goes to D or T; D goes to T (or VI in a deceptive cadence)", "Always alternate SD and D", "Chords in inversion cannot follow each other"], a: 1, fb: "The rule of harmonic functions: T→SD, T→D, SD→D, D→T, D→VI (deceptive cadence). SD→T is the plagal cadence. SD→SD and D→D are possible but in moderation." },
  { q: "Why do we avoid the progression V–IV in strict SATB style?", opts: ["It is too simple", "It represents a backward movement from D to SD — against the natural harmonic flow; the leading tone (in V) seeks to rise, not descend to IV", "It creates augmented fifths", "It does not exist in C major"], a: 1, fb: "V→IV is a backward motion (D→SD). The leading tone (B in C major) in the V chord wants to rise to C (I) — it does not resolve naturally to IV. This progression weakens the tonal feeling and is avoided in strict style." },
  { q: "What progression is correct between two tonic chords?", opts: ["I – I (repetition forbidden)", "I – VI – I or I – I6 – I (legitimate with the same root)", "I can never be followed by another tonic chord", "I must always go to IV or V"], a: 1, fb: "You can move from I to VI (tonic substitute) or from I to I6 (inversion for bass motion). Identical repetition I–I is sterile but not an error. What matters is the overall progression." },
  { q: "In harmonization, what is 'doubling' and what rule applies in root position?", opts: ["Playing two instruments — double any chord freely", "Repeating a chord note in another voice — in root position, double the root preferably", "Adding a seventh to the chord", "Repeating the chord for two measures in a row"], a: 1, fb: "Doubling = writing the same pitch in two different voices (at the octave or unison). In root position, prefer doubling the root. Avoid doubling the leading tone (which must rise) and the third (color of the chord)." },
];

const questionsEs: Question[] = [
  { q: "Una nota de bajo es la fundamental del acorde. ¿En qué estado se encuentra ese acorde?", opts: ["Primera inversión", "Segunda inversión", "Estado fundamental", "Tercera inversión"], a: 2, fb: "Cuando el bajo es la fundamental del acorde, el acorde está en estado fundamental (posición de base). Es la posición más estable, preferida en tiempos fuertes y en cadencias." },
  { q: "Si la nota de bajo es la tercera de un acorde, ¿qué inversión es?", opts: ["Estado fundamental", "Primera inversión (acorde de sexta)", "Segunda inversión (6/4)", "Posición de quinta"], a: 1, fb: "Tercera en el bajo = primera inversión, notado como 'acorde de sexta' (cifrado: 6). Por ejemplo, Do–Mi–Sol con Mi en el bajo da un acorde de Do en primera inversión." },
  { q: "Si la nota de bajo es la quinta de un acorde, ¿qué inversión es?", opts: ["Estado fundamental", "Primera inversión", "Segunda inversión (acorde de cuarta y sexta)", "Posición abierta"], a: 2, fb: "Quinta en el bajo = segunda inversión, notado '6/4' (cifrado: 6 y 4). Es la inversión más inestable — exige una resolución cuidadosa, especialmente como 6/4 de cadencia." },
  { q: "El acorde Do–Mi–Sol con Sol en el bajo corresponde a:", opts: ["I en estado fundamental", "I en primera inversión", "I en segunda inversión", "V6"], a: 2, fb: "Sol es la quinta del acorde de Do mayor. Sol en el bajo = segunda inversión = I6/4 (Do 6/4). Este acorde es muy inestable y aparece principalmente como 6/4 de cadencia." },
  { q: "El acorde Sol–Si–Re con Si en el bajo es:", opts: ["V en estado fundamental", "V6 (primera inversión de V)", "V6/4 (segunda inversión)", "VII en estado fundamental"], a: 1, fb: "Si es la tercera del acorde de Sol mayor. Si en el bajo = primera inversión de V = V6. Esta inversión es muy frecuente y produce un bajo conjunto elegante." },
  { q: "¿Para qué acorde puede Sol en el bajo ser la fundamental?", opts: ["Solo el acorde de Do mayor", "Acorde de Sol mayor (V), Sol menor, Sol7, etc.", "Acorde de Mi menor", "Acorde de Fa mayor"], a: 1, fb: "Sol en el bajo puede ser la fundamental de V (Sol–Si–Re), Solm, Sol7, etc. Por eso hay que analizar la tonalidad y el contexto antes de decidir el acorde." },
  { q: "Cuando la nota de bajo es Sol en Do mayor, ¿qué acordes son posibles con Sol como fundamental?", opts: ["I, IV, II solamente", "V (Sol–Si–Re) y VII (con color disminuido) principalmente", "Solo I6/4", "Solo I en estado fundamental"], a: 1, fb: "En Do mayor, Sol en el bajo como fundamental da principalmente V (Sol–Si–Re). Sol también puede ser la quinta de I (Do–Mi–Sol) en segunda inversión, o la tercera de Mi menor." },
  { q: "Si el bajo es la sensible (7º grado) en Do mayor, ¿qué acorde es obligatorio?", opts: ["VII disminuido en estado fundamental", "V6 (primera inversión de V)", "IV6", "I6"], a: 1, fb: "La sensible (Si en Do mayor) en el bajo impone obligatoriamente V6 — la primera inversión del acorde de dominante. La sensible no puede ser fundamental en el bajo en el estilo estricto." },
  { q: "¿Por qué la sensible en el bajo da V6 y no VIIdim en estado fundamental?", opts: ["Para evitar la quinta disminuida en el bajo", "Porque VIIdim en estado fundamental crea un bajo inestable con quinta disminuida difícil de doblar y resolver", "Por convención arbitraria", "Porque V6 es más fácil de tocar"], a: 1, fb: "VIIdim en estado fundamental (Si–Re–Fa) con Si en el bajo produce una quinta disminuida demasiado inestable. El estilo SATB estricto impone V6: la sensible (Si) es la tercera de Sol–Si–Re, creando una armonía de dominante natural." },
  { q: "En Sol mayor, la sensible es Fa#. Si Fa# está en el bajo, el acorde es:", opts: ["VII en estado fundamental", "V6 en Sol mayor", "II6", "IV6"], a: 1, fb: "En Sol mayor, la sensible es Fa#. Fa# en el bajo = tercera del acorde de Re (V) = V6 en Sol mayor. La regla es absoluta: sensible en el bajo = V6." },
  { q: "En Re menor, la sensible es Do#. Si Do# está en el bajo, el acorde es:", opts: ["VII disminuido en estado fundamental", "V6 en Re menor (menor armónico con sensible elevada)", "IV en Re menor", "I6"], a: 1, fb: "En Re menor, la sensible armónica es Do# (elevada). Do# en el bajo = tercera de La–Do#–Mi (V) = V6 en Re menor. La regla es idéntica en modo menor." },
  { q: "En Do mayor, Fa es el 4º grado. ¿Qué acordes son posibles con Fa en el bajo?", opts: ["I o V solamente", "IV en estado fundamental (Fa–La–Do) o II6 (Re–Fa–La con Fa en el bajo)", "III6 o VII solamente", "V7 o I6/4"], a: 1, fb: "Fa en el bajo en Do mayor puede ser: la fundamental de IV (Fa–La–Do en estado fundamental) o la tercera de II (Re–Fa–La en primera inversión = II6). Ambos son frecuentes según el contexto armónico." },
  { q: "¿Cuál es la diferencia de efecto entre IV en estado fundamental y II6 cuando Fa está en el bajo?", opts: ["Ninguna diferencia", "IV es más estable (fundamental en el bajo), II6 aporta un color más móvil hacia V", "II6 es más estable", "IV siempre resuelve en I, II6 nunca"], a: 1, fb: "IV (Fa–La–Do) es estable en estado fundamental. II6 (Re–Fa–La) con Fa en el bajo es móvil — su resolución natural hacia V crea una progresión SD→D más dinámica." },
  { q: "Sobre el 4º grado en el bajo, ¿qué elección es preferible para preparar una cadencia V–I?", opts: ["IV en estado fundamental", "II6 — porque apunta más directamente hacia V", "I6/4 — para reforzar la cadencia", "VII6"], a: 1, fb: "II6 con Fa en el bajo resuelve muy naturalmente en V. Su tercera (Re) y su fundamental (en las voces superiores) preparan eficazmente la dominante. Es la progresión II6–V–I, muy frecuente." },
  { q: "¿En qué tipo de tiempo puede aparecer el 6/4 de cadencia?", opts: ["En cualquier tiempo", "Solo en un tiempo fuerte", "Solo en un tiempo débil", "Solo en un anacrusis"], a: 1, fb: "El 6/4 de cadencia (I6/4 = quinta de I en el bajo) aparece exclusivamente en un tiempo fuerte. Su resolución en V debe ser inmediata, en el tiempo siguiente." },
  { q: "Después de un 6/4 de cadencia (I6/4 en tiempo fuerte), ¿qué acorde DEBE seguir inmediatamente?", opts: ["I en estado fundamental", "IV", "V (dominante)", "VI"], a: 2, fb: "El 6/4 de cadencia resuelve OBLIGATORIAMENTE en V. La secuencia es: I6/4 (tiempo fuerte) → V → I. Saltarse la resolución en V o ir a otro acorde es una falta grave." },
  { q: "La progresión correcta con un 6/4 de cadencia en Do mayor es:", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I es la progresión cadencial típica. El I6/4 aparece en el tiempo fuerte antes de la dominante. 'Pesa' sobre la quinta de la tónica y resuelve en V." },
  { q: "¿Se puede colocar un 6/4 de cadencia en un tiempo débil?", opts: ["Sí, incluso se recomienda", "No — el 6/4 de cadencia está reservado a los tiempos fuertes exclusivamente", "Sí, pero solo en modo menor", "Sí, si el acorde siguiente es IV"], a: 1, fb: "No — es una falta característica colocar un 6/4 de cadencia en un tiempo débil. El 6/4 de cadencia exige obligatoriamente el tiempo fuerte para tener su peso cadencial y su resolución correcta." },
  { q: "¿Qué ocurre si un 6/4 de cadencia no va seguido de V?", opts: ["Es aceptable en modo menor", "Es una falta grave de contrapunto — la resolución en V es obligatoria", "Se puede ir directamente a I", "Se puede ir a IV"], a: 1, fb: "No resolver I6/4 en V es una falta grave. El 6/4 crea una fuerte tensión (quinta y cuarta con el bajo) que exige resolución en la dominante. La fórmula es invariablemente I6/4 → V → I." },
  { q: "¿Qué acorde representa el bajo en un 6/4 de cadencia en Do mayor?", opts: ["Do (fundamental de I)", "Mi (tercera de I)", "Sol (quinta de I)", "Fa (subdominante)"], a: 2, fb: "En I6/4 en Do mayor, el bajo es Sol (quinta de Do–Mi–Sol). Es esta quinta en el bajo la que crea la inestabilidad característica del 6/4 y exige la resolución en V (que también tiene Sol en el bajo)." },
  { q: "La nota de soprano es Mi en Do mayor. ¿Qué acordes pueden contener Mi?", opts: ["Solo I (Do–Mi–Sol)", "I (Do–Mi–Sol), III (Mi–Sol–Si), VIm (La–Do–Mi)", "Solo V (Sol–Si–Re)", "Solo IV (Fa–La–Do)"], a: 1, fb: "Mi puede ser: la tercera de I (Do–Mi–Sol), la fundamental de III (Mi–Sol–Si), la quinta de VIm (La–Do–Mi). El contexto armónico determina la mejor elección." },
  { q: "La nota de soprano es Sol en Do mayor. ¿Qué acordes pueden contenerla?", opts: ["I, III, V solamente", "I (quinta), III (tercera), V (fundamental), y a veces VIm", "I (quinta), V (fundamental), y también acordes que tienen Sol como fundamental o quinta en la tonalidad", "Solo V"], a: 2, fb: "Sol puede ser: la quinta de I (Do–Mi–Sol), la fundamental de V (Sol–Si–Re), la tercera de Mi menor (III). La lista completa depende de la tonalidad." },
  { q: "La nota de soprano es Si en Do mayor. ¿Qué acordes son compatibles?", opts: ["Solo V (Sol–Si–Re)", "V (fundamental Sol, tercera Si), I (séptima Do–Mi–Sol–Si), VIIdim (Si–Re–Fa)", "Solo III", "I, IV, V, VIIdim"], a: 1, fb: "Si puede ser: la tercera de V (Sol–Si–Re), la 7ª de I7 (Do–Mi–Sol–Si), o la fundamental de VIIdim (Si–Re–Fa). V es la elección más frecuente en estilo SATB." },
  { q: "Al buscar acordes compatibles con una nota de soprano, ¿qué criterio es prioritario?", opts: ["El acorde que suena mejor aislado", "La nota de soprano debe ser fundamental, tercera, quinta o (a veces) séptima del acorde elegido — en la tonalidad", "El acorde más sencillo de realizar", "El acorde con más notas en común con el anterior"], a: 1, fb: "La nota de soprano debe ser una nota constitutiva del acorde (fundamental, tercera, quinta o séptima en el estilo SATB estricto). La tonalidad y la lógica funcional orientan la elección final." },
  { q: "¿Qué es una nota de paso?", opts: ["Una nota tenida de un compás al siguiente", "Una nota extraña al acorde que une por movimiento conjunto dos notas armónicas", "Una nota de adorno por encima o por debajo de una nota real", "Una nota anticipada antes del tiempo"], a: 1, fb: "La nota de paso es una nota no armónica que se desliza por movimiento conjunto entre dos notas armónicas (p. ej. Do–Re–Mi donde Re es de paso). Debe ser breve y no acentuada." },
  { q: "¿Qué es una nota de adorno (bordura)?", opts: ["Una figura ornamental alrededor de una nota real, que vuelve a la misma nota", "Una nota de paso entre dos armonías diferentes", "Un retardo de resolución de una disonancia", "Una anticipación de la nota siguiente"], a: 0, fb: "La nota de adorno gira alrededor de una nota real: nota real → nota adyacente (semitono o tono) → vuelta a la nota real. Ej. Mi–Fa–Mi o Mi–Re#–Mi. La nota central es la nota armónica real." },
  { q: "¿Qué es un retardo?", opts: ["Una nota que llega antes de su acorde", "Una nota armónica prolongada más allá del cambio de acorde, creando una disonancia resuelta por movimiento conjunto descendente", "Una nota de paso no acentuada", "Una nota de adorno a distancia de tercera"], a: 1, fb: "El retardo es una nota tenida desde el acorde anterior que se prolonga en el nuevo acorde, creando una disonancia. Resuelve obligatoriamente por movimiento conjunto descendente. Ej.: 4–3, 7–6, 9–8." },
  { q: "¿Qué es una anticipación?", opts: ["Una nota que llega antes de tiempo perteneciente al acorde siguiente", "Un retardo resuelto hacia arriba", "Una nota de paso en tiempo fuerte", "Una nota de adorno cromática"], a: 0, fb: "La anticipación es una nota que pertenece al acorde siguiente pero llega antes del cambio de acorde. Generalmente es breve, no acentuada, y a menudo en un anacrusis o tiempo débil." },
  { q: "¿Por qué hay que identificar las notas extrañas antes de armonizar un soprano?", opts: ["Para suprimirlas de la melodía", "Para no crear acordes incorrectos sobre notas no reales — armonizar solo las notas estructurales", "Para doblarlas en el tenor", "Para transponerlas a la octava"], a: 1, fb: "Armonizar una nota de paso o bordura como si fuera armónica crea un acorde incorrecto. Primero hay que identificar las notas extrañas, luego armonizar solo las notas reales de la melodía." },
  { q: "En el soprano Sol–Fa–Mi (2 tiempos en Sol, Fa muy breve, Mi), Fa es probablemente:", opts: ["Una nota armónica real que armonizar", "Una nota de paso entre Sol y Mi — no crear un acorde en Fa", "Un retardo de Sol", "Una anticipación de Mi"], a: 1, fb: "Fa breve entre Sol y Mi, por movimiento conjunto descendente, es típicamente una nota de paso. No hay que cambiar de acorde en Fa — se mantiene la armonía de Sol y se cambia en Mi." },
  { q: "En Do mayor, el bajo es Do–Si–La–Fa–Sol–Do. ¿Qué armonización corresponde a I–V6–VI–IV–V–I?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "Do = I (fundamental), Si = V6 (Si = tercera de V en el bajo = 1.ª inversión), La = VI, Fa = IV, Sol = V, Do = I. Progresión clásica T–D–T–SD–D–T." },
  { q: "En Do mayor, ¿cuál es el bajo natural para VI (La menor)?", opts: ["Do", "Mi", "La", "Sol"], a: 2, fb: "La es la fundamental de VI (La–Do–Mi) en Do mayor. La en el bajo = VI en estado fundamental. Es el acorde relativo menor, muy usado después de I o V." },
  { q: "En Do mayor, el bajo Do–Mi–Sol–Mi–Do corresponde a:", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "Do = I (fundamental), Mi = I6 (primera inversión), Sol = I6/4 (segunda inversión), Mi = I6, Do = I. Permanecemos en el acorde de Do con diferentes posiciones — arpegio armónico." },
  { q: "La cadencia perfecta en Do mayor es:", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "La cadencia perfecta = V → I. En Do mayor: Sol–Si–Re → Do–Mi–Sol. Ambos acordes deben estar en estado fundamental para que la cadencia sea 'perfecta' en sentido estricto." },
  { q: "En Sol mayor, la sensible es:", opts: ["Fa natural", "Fa#", "Do", "Mi"], a: 1, fb: "En Sol mayor, la escala es Sol–La–Si–Do–Re–Mi–Fa#–Sol. La sensible (7º grado) es Fa#. En el bajo, Fa# impone V6 (Re–Fa#–La con Fa# en el bajo)." },
  { q: "En Sol mayor, V6 en el bajo corresponde a:", opts: ["Sol en el bajo", "Fa# en el bajo (tercera del acorde de Re = V)", "Mi en el bajo", "Si en el bajo"], a: 1, fb: "En Sol mayor, V = Re–Fa#–La. Fa# es la tercera de este acorde. Fa# en el bajo = V6 (primera inversión de la dominante de Sol mayor)." },
  { q: "En Sol mayor, la progresión I–V–VI–IV–V–I con bajo Sol–Re–Mi–Do–Re–Sol es:", opts: ["Incorrecta — Re en el bajo no es V", "Correcta — Re es la fundamental de V (Re–Fa#–La)", "Correcta pero V debería estar en primera inversión", "Incorrecta — Mi no corresponde a VI"], a: 1, fb: "Sol = I (fundamental), Re = V (fundamental), Mi = VI (Mi–Sol–Si = VIm), Do = IV (Do–Mi–Sol), Re = V, Sol = I. Progresión T–D–T–SD–D–T, enteramente correcta." },
  { q: "En Sol mayor, el acorde IV es:", opts: ["Do–Mi–Sol (Do mayor)", "Re–Fa#–La", "Mi–Sol–Si", "La–Do–Mi"], a: 0, fb: "IV en Sol mayor = Do–Mi–Sol (Do mayor). Construido sobre el 4º grado de Sol mayor (Sol–La–Si–Do), el acorde diatónico es Do–Mi–Sol. Es la subdominante de Sol." },
  { q: "En Re menor armónico, la sensible es:", opts: ["Do natural", "Do#", "Sib", "La"], a: 1, fb: "En Re menor armónico, la 7ª está elevada: Do natural → Do#. Do# es la sensible que asciende a Re (tónica). En el bajo, Do# impone V6 (La–Do#–Mi con Do# en el bajo)." },
  { q: "En Re menor, Sib en el bajo puede corresponder a:", opts: ["IV solamente", "bVI (Sib–Re–Fa = bVI en estado fundamental) o IV6 (Sol–Sib–Re con Sib en el bajo)", "I solamente", "V6"], a: 1, fb: "Sib en el bajo en Re menor puede ser la fundamental de bVI (Sib–Re–Fa, 6º grado bemolizado) o la tercera de IV (Sol–Sib–Re en primera inversión). Ambos son posibles según el contexto." },
  { q: "En Re menor, ¿cuál es el bajo para V en estado fundamental?", opts: ["Re", "La", "Do#", "Sol"], a: 1, fb: "V en Re menor = La–Do#–Mi (dominante armónica). La es la fundamental = La en el bajo = V en estado fundamental. La resolución La→Re es la cadencia perfecta en Re menor." },
  { q: "En Re menor, la progresión Im–V–bVI–IV–V–Im corresponde al bajo:", opts: ["Re–La–Sol–Sib–La–Re", "Re–La–Sib–Sol–La–Re", "La–Re–Sib–Sol–La–Re", "Re–La–Sib–Do#–La–Re"], a: 1, fb: "Im=Re, V=La, bVI=Sib (fundamental de Sib–Re–Fa), IV=Sol (fundamental de Sol–Sib–Re en Re menor), V=La, Im=Re. Bajo: Re–La–Sib–Sol–La–Re." },
  { q: "Sobre la misma nota de bajo, a menudo hay 2–3 acordes posibles. ¿Qué criterio permite elegir?", opts: ["Siempre el mismo acorde independientemente del contexto", "La lógica funcional (T→SD→D→T), la melodía del soprano y la evitación de paralelismos", "El acorde con menos notas alteradas", "El acorde más agudo"], a: 1, fb: "La elección entre varios acordes posibles depende de la lógica funcional (progresión T→SD→D→T), la compatibilidad con el soprano y la evitación de quintas y octavas paralelas." },
  { q: "La nota Re en el bajo en Do mayor puede ser: la fundamental de II (Re–Fa–La) o la quinta de V (Sol–Si–Re). ¿Qué criterio decide?", opts: ["Siempre II porque es la fundamental", "La posición en la frase: II antes de V (SD→D), V6/4 raramente usado; el soprano y el contexto cadencial deciden", "Siempre V6/4", "Se elige al azar"], a: 1, fb: "Si Re en el bajo precede a Sol o Mi, II (Re–Fa–La) es natural como subdominante. Si estamos al final de una frase cadencial con Sol en el soprano, V6/4 puede convenir. El contexto decide." },
  { q: "Sobre La en el bajo en Do mayor, ¿cuáles son los acordes más frecuentes?", opts: ["VIm (La–Do–Mi) o IV6 (Fa–La–Do con La en el bajo)", "I o V solamente", "III o VII", "V o II"], a: 0, fb: "La en el bajo puede ser la fundamental de VIm (La–Do–Mi, 6º grado) o la tercera de IV (Fa–La–Do en primera inversión = IV6). El contexto armónico y la melodía del soprano orientan la elección." },
  { q: "¿Qué es el ritmo armónico?", opts: ["La velocidad a la que toca el baterista", "La frecuencia con que los acordes cambian en una progresión", "El número de voces en el acorde", "La duración de cada nota del soprano"], a: 1, fb: "Ritmo armónico = frecuencia de los cambios de acorde. Rápido = un acorde por tiempo o nota; lento = un acorde por compás o varios compases. Debe adaptarse al tempo y al estilo." },
  { q: "En el estilo SATB estricto, ¿hay que cambiar de acorde en cada nota rápida del soprano?", opts: ["Sí, cada nota debe tener su acorde", "No — las notas rápidas suelen ser notas de paso o borduras; se cambia de acorde en las notas largas/acentuadas", "Sí, pero solo en el soprano", "No, nunca en dos notas consecutivas"], a: 1, fb: "Cambiar de acorde en cada nota rápida es una falta típica. Las notas breves suelen ser extrañas. El ritmo armónico sigue el pulso estructural de la pieza — generalmente la negra o la blanca." },
  { q: "¿Cuál es la señal de que se armoniza demasiado rápido (ritmo armónico demasiado denso)?", opts: ["Acordes demasiado estables", "Frecuentes faltas de quintas u octavas paralelas y cambios de acorde sobre notas no armónicas", "Un soprano demasiado agudo", "Demasiadas inversiones"], a: 1, fb: "Un ritmo armónico demasiado denso provoca cambios de acorde sobre notas extrañas, generando disonancias y paralelismos. La solución: identificar las notas reales y armonizar a una frecuencia más lenta." },
  { q: "En 4/4, ¿cuál es un ritmo armónico frecuente para una armonización DEM de nivel medio?", opts: ["Un acorde cada 2 compases", "Un acorde por compás o un acorde cada dos tiempos (semicopás)", "Un acorde por nota (corchea)", "Cuatro acordes diferentes por compás"], a: 1, fb: "En 4/4, el ritmo armónico estándar es un acorde por compás o cada dos tiempos. Este ritmo deja espacio a las notas extrañas para expresarse sin provocar sobre-armonización." },
  { q: "¿Qué significa la progresión T→SD→D→T en armonización?", opts: ["Tónica hacia subdominante hacia dominante hacia tónica — el ciclo armónico fundamental", "Tenuto, staccato, destacado, tenuto", "Triple, soprano, bajo, tenor", "Tercera, sexta, semitono, tono"], a: 0, fb: "T=Tónica (I, VI), SD=Subdominante (IV, II), D=Dominante (V, VIIdim). La progresión natural T→SD→D→T crea tensión y resolución. En Do mayor: I–IV–V–I." },
  { q: "¿Cuál es el ejemplo típico de la progresión T→SD→D→T en Do mayor?", opts: ["I–V–IV–I", "I–II6–V–I o I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I o I–II6–V–I son las progresiones T→SD→D→T por excelencia. La subdominante (IV o II) precede a la dominante (V) que resuelve en la tónica (I)." },
  { q: "La progresión IV–V–IV en armonización es:", opts: ["Excelente — alterna SD y D", "A evitar — retroceso de V a IV (D→SD) contra el flujo T→SD→D→T", "Neutra — ni buena ni mala", "Obligatoria antes de cualquier cadencia"], a: 1, fb: "IV–V–IV es una falta de progresión: se retrocede de D (V) a SD (IV), contradiciendo el flujo natural. La progresión debe avanzar: SD→D→T. Retroceder debilita la lógica tonal." },
  { q: "VI se clasifica generalmente como:", opts: ["Dominante", "Tónica (sustituto de I)", "Subdominante", "Acorde de paso"], a: 1, fb: "VI (La–Do–Mi en Do mayor) es el relativo menor de I — comparte dos notas con I. Funciona como sustituto de la Tónica y puede reemplazar a I tras una cadencia evitada (V→VI en lugar de V→I)." },
  { q: "II se clasifica generalmente como:", opts: ["Tónica", "Subdominante (comparte dos notas con IV)", "Dominante", "Neutro"], a: 1, fb: "II (Re–Fa–La en Do mayor) es la subdominante — comparte Fa y La con IV (Fa–La–Do). II6 es muy frecuente en armonización antes de V, creando la progresión SD→D." },
  { q: "La cadencia evitada (cadencia interrumpida) ocurre cuando:", opts: ["V resuelve en I como se esperaba", "V resuelve en VI en lugar de I — sorpresa armónica", "IV resuelve en V", "II va directamente a I"], a: 1, fb: "Cadencia evitada = V→VI. En lugar de resolver en I, la dominante se dirige a VI (relativo menor). Es una sorpresa que prolonga la frase y crea interés. La resolución final en I queda diferida." },
  { q: "En una armonización de bajo dado, ¿cómo abordar el final de frase?", opts: ["Terminar en cualquier acorde", "Prever una cadencia clara (V–I o IV–V–I) con los acordes en el orden funcional correcto T→SD→D→T", "Terminar siempre en VI para variedad", "No usar V antes de I"], a: 1, fb: "El final de frase debe planificarse: identificar la cadencia (V–I para cadencia perfecta, IV–I para cadencia plagal, V6/4–V–I para cadencia con 6/4), luego asegurarse de que la progresión lleve a ella lógicamente." },
  { q: "¿Qué regla fundamental guía el encadenamiento de acordes en armonización?", opts: ["Cualquier acorde puede seguir a cualquier otro", "T puede ir a SD o D; SD va a D o T; D va a T (o VI en cadencia evitada)", "Siempre alternar SD y D", "Los acordes en inversión no pueden sucederse"], a: 1, fb: "La regla de las funciones armónicas: T→SD, T→D, SD→D, D→T, D→VI (cadencia evitada). SD→T es la cadencia plagal. SD→SD y D→D son posibles con moderación." },
  { q: "¿Por qué se evita la progresión V–IV en el estilo SATB estricto?", opts: ["Es demasiado sencilla", "Representa un retroceso de D a SD — contra el flujo armónico natural; la sensible (en V) busca subir, no descender hacia IV", "Crea quintas aumentadas", "No existe en Do mayor"], a: 1, fb: "V→IV es un retroceso (D→SD). La sensible (Si en Do mayor) en el acorde de V quiere subir hacia Do (I) — no resuelve naturalmente en IV. Esta progresión debilita el sentido tonal y se evita en el estilo estricto." },
  { q: "¿Qué progresión es correcta entre dos acordes de tónica?", opts: ["I – I (repetición prohibida)", "I – VI – I o I – I6 – I (legítimos con la misma fundamental)", "I nunca puede ir seguido de otro acorde de tónica", "I siempre debe ir a IV o V"], a: 1, fb: "Se puede pasar de I a VI (sustituto de tónica) o de I a I6 (inversión para movimiento de bajo). La repetición idéntica I–I es estéril pero no una falta. Lo importante es la progresión global." },
  { q: "En armonización, ¿qué es una 'duplicación' y qué regla se aplica en estado fundamental?", opts: ["Tocar con dos instrumentos — duplicar libremente cualquier acorde", "Repetir una nota del acorde en otra voz — en estado fundamental, duplicar preferentemente la fundamental", "Añadir una séptima al acorde", "Repetir el acorde dos compases seguidos"], a: 1, fb: "La duplicación = escribir la misma altura en dos voces distintas (a la octava o al unísono). En estado fundamental, se duplica preferentemente la fundamental. Se evita duplicar la sensible (que debe subir) y la tercera (color del acorde)." },
];

const questionsDe: Question[] = [
  { q: "Eine Bassnote ist der Grundton des Akkords. In welcher Lage befindet sich dieser Akkord?", opts: ["Erste Umkehrung", "Zweite Umkehrung", "Grundstellung", "Dritte Umkehrung"], a: 2, fb: "Wenn der Bass der Grundton des Akkords ist, befindet sich der Akkord in der Grundstellung (Basisposition). Dies ist die stabilste Lage, bevorzugt auf schweren Taktzeiten und bei Kadenzen." },
  { q: "Wenn die Bassnote die Terz eines Akkords ist, welche Umkehrung liegt vor?", opts: ["Grundstellung", "Erste Umkehrung (Sextakkord)", "Zweite Umkehrung (Quartsextakkord)", "Quintlage"], a: 1, fb: "Terz im Bass = erste Umkehrung, als 'Sextakkord' notiert (Generalbass-Ziffer: 6). Zum Beispiel gibt C–E–G mit E im Bass einen C-Dur-Akkord in der ersten Umkehrung." },
  { q: "Wenn die Bassnote die Quinte eines Akkords ist, welche Umkehrung liegt vor?", opts: ["Grundstellung", "Erste Umkehrung", "Zweite Umkehrung (Quartsextakkord)", "Offene Lage"], a: 2, fb: "Quinte im Bass = zweite Umkehrung, notiert als '6/4' (Generalbass: 6 und 4). Dies ist die instabilste Umkehrung — sie erfordert eine sorgfältige Auflösung, besonders als Kadenz-Quartsextakkord." },
  { q: "Der Akkord C–E–G mit G im Bass entspricht:", opts: ["I in der Grundstellung", "I in der ersten Umkehrung", "I in der zweiten Umkehrung", "V6"], a: 2, fb: "G ist die Quinte des C-Dur-Akkords. G im Bass = zweite Umkehrung = I6/4 (C 6/4). Dieser Akkord ist sehr instabil und erscheint hauptsächlich als Kadenz-Quartsextakkord." },
  { q: "Der Akkord G–H–D mit H im Bass ist:", opts: ["V in der Grundstellung", "V6 (erste Umkehrung von V)", "V6/4 (zweite Umkehrung)", "VII in der Grundstellung"], a: 1, fb: "H ist die Terz des G-Dur-Akkords. H im Bass = erste Umkehrung von V = V6. Diese Umkehrung ist sehr gebräuchlich und erzeugt einen eleganten Stufengang im Bass." },
  { q: "Als Grundton welches Akkords kann G im Bass dienen?", opts: ["Nur C-Dur-Akkord", "G-Dur-Akkord (V), G-Moll, G7 usw.", "E-Moll-Akkord", "F-Dur-Akkord"], a: 1, fb: "G im Bass kann der Grundton von V (G–H–D), Gm, G7 usw. sein. Daher muss man Tonart und Kontext analysieren, bevor man den Akkord bestimmt." },
  { q: "Wenn die Bassnote G in C-Dur ist, welche Akkorde sind mit G als Grundton möglich?", opts: ["Nur I, IV, II", "V (G–H–D) und VII (mit verminderter Färbung) vorwiegend", "Nur I6/4", "Nur I in der Grundstellung"], a: 1, fb: "In C-Dur ergibt G im Bass als Grundton hauptsächlich V (G–H–D). G kann auch die Quinte von I (C–E–G) in der zweiten Umkehrung sein oder die Terz von E-Moll." },
  { q: "Wenn der Bass der Leitton (7. Stufe) in C-Dur ist, welcher Akkord ist zwingend?", opts: ["Verminderter VII in der Grundstellung", "V6 (erste Umkehrung von V)", "IV6", "I6"], a: 1, fb: "Der Leitton (H in C-Dur) im Bass erzwingt V6 — die erste Umkehrung des Dominantseptakkords. Der Leitton kann im strengen Satz nicht Basston in der Grundstellung sein." },
  { q: "Warum ergibt der Leitton im Bass V6 und nicht VIIdim in der Grundstellung?", opts: ["Um eine verminderte Quinte im Bass zu vermeiden", "Weil VIIdim in der Grundstellung einen instabilen Bass mit verminderter Quinte erzeugt, die schwer zu verdoppeln und aufzulösen ist", "Eine willkürliche Konvention", "Weil V6 leichter zu spielen ist"], a: 1, fb: "VIIdim in der Grundstellung (H–D–F) mit H im Bass erzeugt eine zu instabile verminderte Quinte. Der strenge SATB-Satz schreibt V6 vor: der Leitton (H) ist die Terz von G–H–D und erzeugt so eine natürliche Dominantharmonie." },
  { q: "In G-Dur ist der Leitton Fis. Wenn Fis im Bass liegt, ist der Akkord:", opts: ["VII in der Grundstellung", "V6 in G-Dur", "II6", "IV6"], a: 1, fb: "In G-Dur ist der Leitton Fis. Fis im Bass = Terz des D-Akkords (V) = V6 in G-Dur. Die Regel ist absolut: Leitton im Bass = V6." },
  { q: "In D-Moll ist der Leitton Cis. Wenn Cis im Bass liegt, ist der Akkord:", opts: ["Verminderter VII in der Grundstellung", "V6 in D-Moll (harmonisches Moll mit erhöhtem Leitton)", "IV in D-Moll", "I6"], a: 1, fb: "In D-Moll ist der harmonische Leitton Cis (erhöht). Cis im Bass = Terz von A–Cis–E (V) = V6 in D-Moll. Die Regel gilt identisch im Moll." },
  { q: "In C-Dur ist F die 4. Stufe. Welche Akkorde sind mit F im Bass möglich?", opts: ["Nur I oder V", "IV in der Grundstellung (F–A–C) oder II6 (D–F–A mit F im Bass)", "Nur III6 oder VII", "V7 oder I6/4"], a: 1, fb: "F im Bass in C-Dur kann sein: der Grundton von IV (F–A–C in der Grundstellung) oder die Terz von II (D–F–A in der ersten Umkehrung = II6). Beide sind je nach harmonischem Kontext gebräuchlich." },
  { q: "Was ist der Unterschied zwischen IV in der Grundstellung und II6, wenn F im Bass liegt?", opts: ["Kein Unterschied", "IV ist stabiler (Grundton im Bass), II6 bringt eine beweglichere Färbung hin zu V", "II6 ist stabiler", "IV löst immer nach I auf, II6 nie"], a: 1, fb: "IV (F–A–C) ist in der Grundstellung stabil. II6 (D–F–A) mit F im Bass ist beweglich — seine natürliche Auflösung nach V erzeugt eine dynamischere SD→D-Progression." },
  { q: "Über der 4. Stufe im Bass: Welche Wahl ist vorzuziehen, um eine V–I-Kadenz vorzubereiten?", opts: ["IV in der Grundstellung", "II6 — da er direkter auf V zuweist", "I6/4 — um die Kadenz zu verstärken", "VII6"], a: 1, fb: "II6 mit F im Bass löst sehr natürlich nach V auf. Seine Terz (D) und sein Grundton (in den Oberstimmen) bereiten die Dominante wirksam vor. Dies ist die Progression II6–V–I, sehr häufig." },
  { q: "Auf welchem Taktzeitteil kann der Kadenz-Quartsextakkord erscheinen?", opts: ["Auf beliebigen Taktzeiten", "Nur auf einem schweren Taktteil", "Nur auf einem leichten Taktteil", "Nur auf einem Auftakt"], a: 1, fb: "Der Kadenz-Quartsextakkord (I6/4 = Quinte von I im Bass) erscheint ausschließlich auf einem schweren Taktteil. Seine Auflösung nach V muss unmittelbar folgen." },
  { q: "Nach einem Kadenz-Quartsextakkord (I6/4 auf schwerem Taktteil), welcher Akkord MUSS unmittelbar folgen?", opts: ["I in der Grundstellung", "IV", "V (Dominante)", "VI"], a: 2, fb: "Der Kadenz-Quartsextakkord löst OBLIGATORISCH nach V auf. Die Folge lautet: I6/4 (schwerer Taktteil) → V → I. Den Schritt nach V zu überspringen oder zu einem anderen Akkord zu gehen ist ein schwerer Fehler." },
  { q: "Die korrekte Progression mit einem Kadenz-Quartsextakkord in C-Dur lautet:", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I ist die typische Kadenzprogression. I6/4 erscheint auf dem schweren Taktteil vor der Dominante. Er 'lastet' auf der Quinte der Tonika und löst nach V auf." },
  { q: "Kann ein Kadenz-Quartsextakkord auf einem leichten Taktteil stehen?", opts: ["Ja, das wird sogar empfohlen", "Nein — der Kadenz-Quartsextakkord ist ausschließlich schweren Taktteilen vorbehalten", "Ja, aber nur in Moll", "Ja, wenn der folgende Akkord IV ist"], a: 1, fb: "Nein — es ist ein charakteristischer Fehler, einen Kadenz-Quartsextakkord auf einem leichten Taktteil zu platzieren. Er erfordert zwingend den schweren Taktteil für sein Kadenzgewicht und die korrekte Auflösung." },
  { q: "Was geschieht, wenn ein Kadenz-Quartsextakkord nicht von V gefolgt wird?", opts: ["Es ist in Moll akzeptabel", "Es ist ein schwerer Kontrapunktfehler — die Auflösung nach V ist zwingend", "Man kann direkt nach I gehen", "Man kann nach IV gehen"], a: 1, fb: "I6/4 nicht nach V aufzulösen ist ein schwerer Fehler. Der 6/4 erzeugt starke Spannung (Quinte und Quarte gegen den Bass), die eine Auflösung zur Dominante verlangt. Die Formel lautet stets I6/4 → V → I." },
  { q: "Welchen Akkord vertritt der Bass in einem Kadenz-Quartsextakkord in C-Dur?", opts: ["C (Grundton von I)", "E (Terz von I)", "G (Quinte von I)", "F (Subdominante)"], a: 2, fb: "In I6/4 in C-Dur liegt G im Bass (Quinte von C–E–G). Diese Quinte im Bass erzeugt die charakteristische Instabilität des 6/4 und fordert die Auflösung nach V (das ebenfalls G im Bass hat)." },
  { q: "Die Sopranote ist E in C-Dur. Welche Akkorde können E enthalten?", opts: ["Nur I (C–E–G)", "I (C–E–G), III (E–G–H), VIm (A–C–E)", "Nur V (G–H–D)", "Nur IV (F–A–C)"], a: 1, fb: "E kann sein: die Terz von I (C–E–G), der Grundton von III (E–G–H), die Quinte von VIm (A–C–E). Der harmonische Kontext bestimmt die beste Wahl." },
  { q: "Die Sopranote ist G in C-Dur. Welche Akkorde können sie enthalten?", opts: ["Nur I, III, V", "I (Quinte), III (Terz), V (Grundton) und manchmal VIm", "I (Quinte), V (Grundton) sowie Akkorde, die G als Grundton oder Quinte in der Tonart haben", "Nur V"], a: 2, fb: "G kann sein: die Quinte von I (C–E–G), der Grundton von V (G–H–D), die Terz von E-Moll (III). Die vollständige Liste hängt von der Tonart ab." },
  { q: "Die Sopranote ist H in C-Dur. Welche Akkorde sind kompatibel?", opts: ["Nur V (G–H–D)", "V (Grundton G, Terz H), I (Septakkord C–E–G–H), VIIdim (H–D–F)", "Nur III", "I, IV, V, VIIdim"], a: 1, fb: "H kann sein: die Terz von V (G–H–D), die Sept von I7 (C–E–G–H) oder der Grundton von VIIdim (H–D–F). V ist die häufigste Wahl im SATB-Satz." },
  { q: "Welches Kriterium hat Vorrang beim Suchen nach Akkorden, die mit einer Sopranote kompatibel sind?", opts: ["Der Akkord, der isoliert am besten klingt", "Die Sopranote muss Grundton, Terz, Quinte oder (manchmal) Sept des gewählten Akkords sein — innerhalb der Tonart", "Der einfachste zu realisierende Akkord", "Der Akkord mit den meisten gemeinsamen Noten zum vorherigen"], a: 1, fb: "Die Sopranote muss eine konstitutive Note des Akkords sein (Grundton, Terz, Quinte oder Sept im strengen SATB-Satz). Tonart und Funktionslogik leiten die endgültige Wahl." },
  { q: "Was ist ein Durchgangs­ton?", opts: ["Eine von Takt zu Takt gehaltene Note", "Eine akkord­fremde Note, die zwei Akkordnoten durch Stufengang verbindet", "Eine Wechselnote ober- oder unterhalb einer echten Note", "Eine Note, die vor dem Taktschlag antizipiert wird"], a: 1, fb: "Der Durchgangston ist eine nicht-harmonische Note, die sich stufenweise zwischen zwei Akkordtöne schiebt (z. B. C–D–E, wo D Durchgangs­ton ist). Er muss kurz und unbetont sein." },
  { q: "Was ist eine Wechselnote?", opts: ["Eine ornamentale Figur um eine echte Note, die zur selben Note zurückkehrt", "Eine Durchgangs­note zwischen zwei verschiedenen Harmonien", "Eine verzögerte Auflösung einer Dissonanz", "Eine Antizipation der nächsten Note"], a: 0, fb: "Die Wechselnote umkreist eine echte Note: echte Note → benachbarte Note (Halb- oder Ganzton) → Rückkehr zur echten Note. z. B. E–F–E oder E–Dis–E. Die mittlere Note ist die echte Akkordnote." },
  { q: "Was ist ein Vorhalt?", opts: ["Eine Note, die vor ihrem Akkord ankommt", "Eine Akkordnote, die über einen Akkordwechsel hinaus gehalten wird, eine Dissonanz erzeugt und durch Stufengang abwärts auflöst", "Ein unbetonter Durchgangs­ton", "Eine Wechselnote im Terzabstand"], a: 1, fb: "Der Vorhalt ist eine Note, die vom vorherigen Akkord gehalten wird und in den neuen Akkord hineinragt, eine Dissonanz bildend. Sie löst obligatorisch durch Stufengang abwärts auf. z. B.: 4–3, 7–6, 9–8." },
  { q: "Was ist eine Antizipation?", opts: ["Eine Note, die vorzeitig zum nächsten Akkord gehört", "Ein Vorhalt, der nach oben auflöst", "Ein betonter Durchgangs­ton", "Eine chromatische Wechselnote"], a: 0, fb: "Die Antizipation ist eine Note, die zum nächsten Akkord gehört, aber vor dem Akkordwechsel erscheint. Sie ist in der Regel kurz, unbetont und oft auf einem Auftakt oder leichten Taktteil." },
  { q: "Warum muss man akkord­fremde Noten identifizieren, bevor man einen Sopran harmonisiert?", opts: ["Um sie aus der Melodie zu entfernen", "Um keine falschen Akkorde auf Nicht-Akkordtönen zu bilden — nur die strukturellen Töne harmonisieren", "Um sie im Tenor zu verdoppeln", "Um sie in die Oktave zu transponieren"], a: 1, fb: "Einen Durchgangs­ton oder eine Wechselnote als Akkordton zu harmonisieren erzeugt einen falschen Akkord. Zuerst die akkord­fremden Noten identifizieren, dann nur die echten Melodietöne harmonisieren." },
  { q: "Im Sopran G–F–E (2 Taktzeiten auf G, F sehr kurz, E), ist F wahrscheinlich:", opts: ["Ein echter Akkordton, der zu harmonisieren ist", "Ein Durchgangs­ton zwischen G und E — keinen Akkord auf F bilden", "Ein Vorhalt von G", "Eine Antizipation von E"], a: 1, fb: "F kurz zwischen G und E, durch Stufengang abwärts, ist typischerweise ein Durchgangs­ton. Den Akkord auf F nicht wechseln — die G-Harmonie beibehalten, dann auf E wechseln." },
  { q: "In C-Dur ist der Bass C–H–A–F–G–C. Welche Harmonisierung entspricht I–V6–VI–IV–V–I?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "C = I (Grundton), H = V6 (H = Terz von V im Bass = erste Umkehrung), A = VI, F = IV, G = V, C = I. Klassische Progression T–D–T–SD–D–T." },
  { q: "In C-Dur, welches ist der natürliche Bass für VI (A-Moll)?", opts: ["C", "E", "A", "G"], a: 2, fb: "A ist der Grundton von VI (A–C–E) in C-Dur. A im Bass = VI in der Grundstellung. Dies ist der parallele Mollakkord, sehr gebräuchlich nach I oder V." },
  { q: "In C-Dur entspricht der Bass C–E–G–E–C:", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "C = I (Grundton), E = I6 (erste Umkehrung), G = I6/4 (zweite Umkehrung), E = I6, C = I. Wir bleiben auf dem C-Akkord in verschiedenen Lagen — harmonisches Arpeggio." },
  { q: "Die vollkommene Kadenz in C-Dur lautet:", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "Die vollkommene Kadenz = V → I. In C-Dur: G–H–D → C–E–G. Beide Akkorde müssen in der Grundstellung stehen, damit die Kadenz im strengen Sinne 'vollkommen' ist." },
  { q: "In G-Dur ist der Leitton:", opts: ["F (Naturton)", "Fis", "C", "E"], a: 1, fb: "In G-Dur lautet die Tonleiter G–A–H–C–D–E–Fis–G. Der Leitton (7. Stufe) ist Fis. Im Bass erzwingt Fis V6 (D–Fis–A mit Fis im Bass)." },
  { q: "In G-Dur entspricht V6 im Bass:", opts: ["G im Bass", "Fis im Bass (Terz des D-Akkords = V)", "E im Bass", "H im Bass"], a: 1, fb: "In G-Dur ist V = D–Fis–A. Fis ist die Terz dieses Akkords. Fis im Bass = V6 (erste Umkehrung der Dominante von G-Dur)." },
  { q: "In G-Dur ist die Progression I–V–VI–IV–V–I mit Bass G–D–E–C–D–G:", opts: ["Falsch — D im Bass ist nicht V", "Richtig — D ist der Grundton von V (D–Fis–A)", "Richtig, aber V sollte in der ersten Umkehrung stehen", "Falsch — E entspricht nicht VI"], a: 1, fb: "G = I (Grundton), D = V (Grundton), E = VI (E–G–H = VIm), C = IV (C–E–G), D = V, G = I. Progression T–D–T–SD–D–T, vollständig korrekt." },
  { q: "In G-Dur ist der IV-Akkord:", opts: ["C–E–G (C-Dur)", "D–Fis–A", "E–G–H", "A–C–E"], a: 0, fb: "IV in G-Dur = C–E–G (C-Dur). Auf der 4. Stufe von G-Dur (G–A–H–C) aufgebaut, ist der diatonische Akkord C–E–G. Dies ist die Subdominante von G." },
  { q: "In D-harmonisch-Moll ist der Leitton:", opts: ["C (Naturton)", "Cis", "B", "A"], a: 1, fb: "In D-harmonisch-Moll wird die 7. Stufe erhöht: C → Cis. Cis ist der Leitton, der nach D (Tonika) aufsteigt. Im Bass erzwingt Cis V6 (A–Cis–E mit Cis im Bass)." },
  { q: "In D-Moll kann B im Bass entsprechen:", opts: ["Nur IV", "bVI (B–D–F = bVI in der Grundstellung) oder IV6 (G–B–D mit B im Bass)", "Nur I", "V6"], a: 1, fb: "B im Bass in D-Moll kann der Grundton von bVI (B–D–F, erniedrigte 6. Stufe) oder die Terz von IV (G–B–D in der ersten Umkehrung) sein. Beide sind je nach Kontext möglich." },
  { q: "In D-Moll, welches ist der Bass für V in der Grundstellung?", opts: ["D", "A", "Cis", "G"], a: 1, fb: "V in D-Moll = A–Cis–E (harmonische Dominante). A ist der Grundton = A im Bass = V in der Grundstellung. Die Auflösung A→D ist die vollkommene Kadenz in D-Moll." },
  { q: "In D-Moll entspricht die Progression Im–V–bVI–IV–V–Im dem Bass:", opts: ["D–A–G–B–A–D", "D–A–B–G–A–D", "A–D–B–G–A–D", "D–A–B–Cis–A–D"], a: 1, fb: "Im=D, V=A, bVI=B (Grundton von B–D–F), IV=G (Grundton von G–B–D in D-Moll), V=A, Im=D. Bass: D–A–B–G–A–D." },
  { q: "Über derselben Bassnote gibt es oft 2–3 mögliche Akkorde. Welches Kriterium hilft bei der Wahl?", opts: ["Stets denselben Akkord unabhängig vom Kontext", "Funktionale Logik (T→SD→D→T), die Sopranmelodie und Vermeidung von Parallelismus", "Den Akkord mit den wenigsten Alterationen", "Den höchsten Akkord"], a: 1, fb: "Die Wahl zwischen mehreren möglichen Akkorden hängt von der Funktionslogik (T→SD→D→T), der Kompatibilität mit dem Sopran und der Vermeidung von Quinten- und Oktavparallelen ab." },
  { q: "Die Note D im Bass in C-Dur kann sein: Grundton von II (D–F–A) oder Quinte von V (G–H–D). Was entscheidet?", opts: ["Stets II, weil es der Grundton ist", "Position in der Phrase: II vor V (SD→D), V6/4 selten; Sopran und kadentieller Kontext entscheiden", "Stets V6/4", "Man wählt zufällig"], a: 1, fb: "Wenn D im Bass G oder E vorausgeht, ist II (D–F–A) als Subdominante natürlich. Steht man am Ende einer Kadenzphrase mit G im Sopran, kann V6/4 passen. Der Kontext entscheidet." },
  { q: "Über A im Bass in C-Dur, welche Akkorde sind am gebräuchlichsten?", opts: ["VIm (A–C–E) oder IV6 (F–A–C mit A im Bass)", "Nur I oder V", "III oder VII", "V oder II"], a: 0, fb: "A im Bass kann der Grundton von VIm (A–C–E, 6. Stufe) oder die Terz von IV (F–A–C in der ersten Umkehrung = IV6) sein. Harmonischer Kontext und Sopranmelodie leiten die Wahl." },
  { q: "Was ist harmonischer Rhythmus?", opts: ["Die Geschwindigkeit, mit der der Schlagzeuger spielt", "Die Häufigkeit, mit der Akkorde in einer Progression wechseln", "Die Anzahl der Stimmen im Akkord", "Die Dauer jeder Sopranote"], a: 1, fb: "Harmonischer Rhythmus = Häufigkeit der Akkordwechsel. Schnell = ein Akkord pro Zählzeit oder Note; langsam = ein Akkord pro Takt oder mehrere Takte. Er muss an Tempo und Stil angepasst werden." },
  { q: "Im strengen SATB-Satz: Muss man auf jede schnelle Sopranote den Akkord wechseln?", opts: ["Ja, jede Note muss ihren Akkord haben", "Nein — schnelle Noten sind oft Durchgangstöne oder Wechselnoten; Akkordwechsel erfolgen auf langen/betonten Noten", "Ja, aber nur im Sopran", "Nein, niemals auf zwei aufeinanderfolgenden Noten"], a: 1, fb: "Auf jede schnelle Note den Akkord zu wechseln ist ein typischer Fehler. Kurze Noten sind oft akkord­fremd. Der harmonische Rhythmus folgt dem strukturellen Puls des Stücks — in der Regel die Viertelnote oder halbe Note." },
  { q: "Was ist das Zeichen dafür, dass man zu schnell harmonisiert (zu dichter harmonischer Rhythmus)?", opts: ["Zu stabile Akkorde", "Häufige Quinten- oder Oktavparallelen und Akkordwechsel auf Nicht-Akkordtönen", "Ein zu hoher Sopran", "Zu viele Umkehrungen"], a: 1, fb: "Ein zu dichter harmonischer Rhythmus führt zu Akkordwechseln auf akkord­fremden Noten, was Dissonanzen und Parallelen erzeugt. Lösung: echte Noten identifizieren und in langsamerem Rhythmus harmonisieren." },
  { q: "In 4/4: Welcher harmonische Rhythmus ist für eine Harmonisierungsaufgabe mittlerer Schwierigkeit gebräuchlich?", opts: ["Ein Akkord alle 2 Takte", "Ein Akkord pro Takt oder ein Akkord alle zwei Zählzeiten (halber Takt)", "Ein Akkord pro Note (Achtel)", "Vier verschiedene Akkorde pro Takt"], a: 1, fb: "In 4/4 ist der Standardrhythmus ein Akkord pro Takt oder alle zwei Zählzeiten. Dieses Tempo lässt akkord­fremden Noten Raum zur Entfaltung, ohne zu über-harmonisieren." },
  { q: "Was bedeutet die Progression T→SD→D→T in der Harmonisierung?", opts: ["Tonika zu Subdominante zu Dominante zu Tonika — der fundamentale harmonische Kreislauf", "Tenuto, Stakkato, getragen, Tenuto", "Diskant, Sopran, Bass, Tenor", "Terz, Sexte, Halbton, Ganzton"], a: 0, fb: "T=Tonika (I, VI), SD=Subdominante (IV, II), D=Dominante (V, VIIdim). Die natürliche Progression T→SD→D→T erzeugt Spannung und Auflösung. In C-Dur: I–IV–V–I." },
  { q: "Was ist das typische Beispiel der T→SD→D→T-Progression in C-Dur?", opts: ["I–V–IV–I", "I–II6–V–I oder I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I oder I–II6–V–I sind die T→SD→D→T-Progressionen par excellence. Die Subdominante (IV oder II) geht der Dominante (V) voraus, die zur Tonika (I) auflöst." },
  { q: "Die Progression IV–V–IV in der Harmonisierung ist:", opts: ["Ausgezeichnet — wechselt SD und D ab", "Zu vermeiden — Rückschritt von V nach IV (D→SD) entgegen dem T→SD→D→T-Fluss", "Neutral — weder gut noch schlecht", "Vor jeder Kadenz obligatorisch"], a: 1, fb: "IV–V–IV ist ein Progressionsfehler: Rückschritt von D (V) nach SD (IV) widerspricht dem natürlichen Fluss. Die Progression muss vorwärtsgehen: SD→D→T. Rückwärtsgehen schwächt die Tonalität." },
  { q: "VI wird üblicherweise klassifiziert als:", opts: ["Dominante", "Tonika (Substitut für I)", "Subdominante", "Durchgangsakkord"], a: 1, fb: "VI (A–C–E in C-Dur) ist die Tonikaparallele — er teilt zwei Noten mit I. Er fungiert als Tonikasubstitut und kann I nach einem Trugschluss ersetzen (V→VI statt V→I)." },
  { q: "II wird üblicherweise klassifiziert als:", opts: ["Tonika", "Subdominante (teilt zwei Noten mit IV)", "Dominante", "Neutral"], a: 1, fb: "II (D–F–A in C-Dur) ist die Subdominante — er teilt F und A mit IV (F–A–C). II6 ist in der Harmonisierung sehr häufig vor V und erzeugt die SD→D-Progression." },
  { q: "Der Trugschluss tritt auf, wenn:", opts: ["V wie erwartet nach I auflöst", "V nach VI statt nach I auflöst — harmonische Überraschung", "IV nach V auflöst", "II direkt nach I geht"], a: 1, fb: "Trugschluss = V→VI. Statt nach I aufzulösen, geht die Dominante nach VI (Tonikaparallele). Dies ist eine Überraschung, die die Phrase verlängert und Interesse weckt. Die endgültige Auflösung nach I wird aufgeschoben." },
  { q: "In einer Bassharmonisierung: Wie nähert man sich dem Phrasenende?", opts: ["Auf einem beliebigen Akkord enden", "Eine klare Kadenz planen (V–I oder IV–V–I) mit Akkorden in der richtigen Funktionsreihenfolge T→SD→D→T", "Immer auf VI enden zur Abwechslung", "Nie V vor I verwenden"], a: 1, fb: "Das Phrasenende muss geplant werden: Kadenz identifizieren (V–I für vollkommene Kadenz, IV–I für Plagalkadenz, V6/4–V–I für Kadenz mit 6/4), dann sicherstellen, dass die Progression logisch dorthin führt." },
  { q: "Welche Grundregel leitet die Akkordfolge in der Harmonisierung?", opts: ["Jeder Akkord kann jedem anderen folgen", "T kann nach SD oder D gehen; SD geht nach D oder T; D geht nach T (oder VI im Trugschluss)", "Immer SD und D abwechseln", "Akkorde in Umkehrung können nicht aufeinanderfolgen"], a: 1, fb: "Die Regel der harmonischen Funktionen: T→SD, T→D, SD→D, D→T, D→VI (Trugschluss). SD→T ist die Plagalkadenz. SD→SD und D→D sind mit Maß möglich." },
  { q: "Warum vermeidet man die Progression V–IV im strengen SATB-Satz?", opts: ["Sie ist zu einfach", "Sie stellt einen Rückschritt von D nach SD dar — gegen den natürlichen harmonischen Fluss; der Leitton (in V) strebt aufwärts, nicht abwärts nach IV", "Sie erzeugt übermäßige Quinten", "Sie existiert in C-Dur nicht"], a: 1, fb: "V→IV ist ein Rückschritt (D→SD). Der Leitton (H in C-Dur) im V-Akkord strebt nach C (I) — er löst nicht natürlich nach IV auf. Diese Progression schwächt das Tonalitätsgefühl und wird im strengen Satz vermieden." },
  { q: "Welche Progression ist zwischen zwei Tonikaakkorden korrekt?", opts: ["I – I (Wiederholung verboten)", "I – VI – I oder I – I6 – I (zulässig mit demselben Grundton)", "I kann nie von einem anderen Tonikaakkord gefolgt werden", "I muss immer nach IV oder V gehen"], a: 1, fb: "Man kann von I nach VI (Tonikasubstitut) oder von I nach I6 (Umkehrung für Bassbewegung) gehen. Identische Wiederholung I–I ist steril, aber kein Fehler. Entscheidend ist die Gesamtprogression." },
  { q: "Was ist in der Harmonisierung eine 'Verdopplung' und welche Regel gilt in der Grundstellung?", opts: ["Mit zwei Instrumenten spielen — jeden Akkord frei verdoppeln", "Dieselbe Tonhöhe in einer anderen Stimme wiederholen — in der Grundstellung vorzugsweise den Grundton verdoppeln", "Eine Septime zum Akkord hinzufügen", "Den Akkord zwei Takte wiederholen"], a: 1, fb: "Verdopplung = dieselbe Tonhöhe in zwei verschiedenen Stimmen schreiben (in der Oktave oder Unisono). In der Grundstellung wird bevorzugt der Grundton verdoppelt. Den Leitton (der aufsteigen muss) und die Terz (Akkordfarbe) vermeidet man zu verdoppeln." },
];

const questionsIt: Question[] = [
  { q: "Una nota di basso è la fondamentale dell'accordo. In quale posizione si trova quest'accordo?", opts: ["Primo rivolto", "Secondo rivolto", "Posizione fondamentale", "Terzo rivolto"], a: 2, fb: "Quando il basso è la fondamentale dell'accordo, l'accordo è in posizione fondamentale (posizione di base). È la posizione più stabile, preferita sui tempi forti e alle cadenze." },
  { q: "Se la nota di basso è la terza di un accordo, quale rivolto è?", opts: ["Posizione fondamentale", "Primo rivolto (accordo di sesta)", "Secondo rivolto (accordo di quarta e sesta)", "Posizione di quinta"], a: 1, fb: "Terza al basso = primo rivolto, notato come 'accordo di sesta' (cifratura: 6). Ad esempio, Do–Mi–Sol con Mi al basso dà un accordo di Do in primo rivolto." },
  { q: "Se la nota di basso è la quinta di un accordo, quale rivolto è?", opts: ["Posizione fondamentale", "Primo rivolto", "Secondo rivolto (accordo di quarta e sesta)", "Posizione aperta"], a: 2, fb: "Quinta al basso = secondo rivolto, notato '6/4' (cifratura: 6 e 4). È il rivolto più instabile — richiede una risoluzione attenta, specialmente come accordo di 6/4 cadenziale." },
  { q: "L'accordo Do–Mi–Sol con Sol al basso corrisponde a:", opts: ["I in posizione fondamentale", "I in primo rivolto", "I in secondo rivolto", "V6"], a: 2, fb: "Sol è la quinta dell'accordo di Do maggiore. Sol al basso = secondo rivolto = I6/4 (Do 6/4). Quest'accordo è molto instabile e compare principalmente come 6/4 cadenziale." },
  { q: "L'accordo Sol–Si–Re con Si al basso è:", opts: ["V in posizione fondamentale", "V6 (primo rivolto di V)", "V6/4 (secondo rivolto)", "VII in posizione fondamentale"], a: 1, fb: "Si è la terza dell'accordo di Sol maggiore. Si al basso = primo rivolto di V = V6. Questo rivolto è molto comune e produce un basso per gradi elegante." },
  { q: "Come fondamentale di quale accordo può servire Sol al basso?", opts: ["Solo l'accordo di Do maggiore", "Accordo di Sol maggiore (V), Sol minore, Sol7, ecc.", "Accordo di Mi minore", "Accordo di Fa maggiore"], a: 1, fb: "Sol al basso può essere la fondamentale di V (Sol–Si–Re), Solm, Sol7, ecc. Bisogna quindi analizzare la tonalità e il contesto prima di decidere l'accordo." },
  { q: "Quando la nota di basso è Sol in Do maggiore, quali accordi sono possibili con Sol come fondamentale?", opts: ["Solo I, IV, II", "V (Sol–Si–Re) e VII (con colore diminuito) principalmente", "Solo I6/4", "Solo I in posizione fondamentale"], a: 1, fb: "In Do maggiore, Sol al basso come fondamentale dà principalmente V (Sol–Si–Re). Sol può anche essere la quinta di I (Do–Mi–Sol) in secondo rivolto, o la terza di Mi minore." },
  { q: "Se il basso è la sensibile (7° grado) in Do maggiore, quale accordo è obbligatorio?", opts: ["VII diminuito in posizione fondamentale", "V6 (primo rivolto di V)", "IV6", "I6"], a: 1, fb: "La sensibile (Si in Do maggiore) al basso impone obbligatoriamente V6 — il primo rivolto dell'accordo di dominante. La sensibile non può essere fondamentale al basso nello stile rigoroso." },
  { q: "Perché la sensibile al basso dà V6 e non VIIdim in posizione fondamentale?", opts: ["Per evitare la quinta diminuita al basso", "Perché VIIdim in posizione fondamentale crea un basso instabile con quinta diminuita difficile da raddoppiare e risolvere", "Per convenzione arbitraria", "Perché V6 è più facile da suonare"], a: 1, fb: "VIIdim in posizione fondamentale (Si–Re–Fa) con Si al basso produce una quinta diminuita troppo instabile. Lo stile SATB rigoroso impone V6: la sensibile (Si) è la terza di Sol–Si–Re, creando un'armonia di dominante naturale." },
  { q: "In Sol maggiore, la sensibile è Fa#. Se Fa# è al basso, l'accordo è:", opts: ["VII in posizione fondamentale", "V6 in Sol maggiore", "II6", "IV6"], a: 1, fb: "In Sol maggiore, la sensibile è Fa#. Fa# al basso = terza dell'accordo di Re (V) = V6 in Sol maggiore. La regola è assoluta: sensibile al basso = V6." },
  { q: "In Re minore, la sensibile è Do#. Se Do# è al basso, l'accordo è:", opts: ["VII diminuito in posizione fondamentale", "V6 in Re minore (minore armonico con sensibile alzata)", "IV in Re minore", "I6"], a: 1, fb: "In Re minore, la sensibile armonica è Do# (alzata). Do# al basso = terza di La–Do#–Mi (V) = V6 in Re minore. La regola è identica in modo minore." },
  { q: "In Do maggiore, Fa è il 4° grado. Quali accordi sono possibili con Fa al basso?", opts: ["Solo I o V", "IV in posizione fondamentale (Fa–La–Do) o II6 (Re–Fa–La con Fa al basso)", "Solo III6 o VII", "V7 o I6/4"], a: 1, fb: "Fa al basso in Do maggiore può essere: la fondamentale di IV (Fa–La–Do in posizione fondamentale) o la terza di II (Re–Fa–La in primo rivolto = II6). Entrambi sono frequenti a seconda del contesto armonico." },
  { q: "Qual è la differenza di effetto tra IV in posizione fondamentale e II6 quando Fa è al basso?", opts: ["Nessuna differenza", "IV è più stabile (fondamentale al basso), II6 apporta un colore più mobile verso V", "II6 è più stabile", "IV risolve sempre su I, II6 mai"], a: 1, fb: "IV (Fa–La–Do) è stabile in posizione fondamentale. II6 (Re–Fa–La) con Fa al basso è mobile — la sua risoluzione naturale verso V crea una progressione SD→D più dinamica." },
  { q: "Sul 4° grado al basso, quale scelta è preferibile per preparare una cadenza V–I?", opts: ["IV in posizione fondamentale", "II6 — perché punta più direttamente verso V", "I6/4 — per rafforzare la cadenza", "VII6"], a: 1, fb: "II6 con Fa al basso risolve molto naturalmente su V. La sua terza (Re) e la sua fondamentale (nelle voci superiori) preparano efficacemente la dominante. Questa è la progressione II6–V–I, molto frequente." },
  { q: "Su quale tipo di tempo può apparire il 6/4 cadenziale?", opts: ["Su qualsiasi tempo", "Solo su un tempo forte", "Solo su un tempo debole", "Solo su una levare"], a: 1, fb: "Il 6/4 cadenziale (I6/4 = quinta di I al basso) appare esclusivamente su un tempo forte. La sua risoluzione su V deve essere immediata, al tempo seguente." },
  { q: "Dopo un 6/4 cadenziale (I6/4 su tempo forte), quale accordo DEVE seguire immediatamente?", opts: ["I in posizione fondamentale", "IV", "V (dominante)", "VI"], a: 2, fb: "Il 6/4 cadenziale risolve OBBLIGATORIAMENTE su V. La sequenza è: I6/4 (tempo forte) → V → I. Saltare la risoluzione su V o andare a un altro accordo è una grave mancanza." },
  { q: "La progressione corretta con un 6/4 cadenziale in Do maggiore è:", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I è la progressione cadenziale tipica. Il I6/4 appare sul tempo forte prima della dominante. 'Pesa' sulla quinta della tonica e risolve su V." },
  { q: "Si può collocare un 6/4 cadenziale su un tempo debole?", opts: ["Sì, è addirittura raccomandato", "No — il 6/4 cadenziale è riservato esclusivamente ai tempi forti", "Sì, ma solo in modo minore", "Sì, se l'accordo seguente è IV"], a: 1, fb: "No — è un errore caratteristico collocare un 6/4 cadenziale su un tempo debole. Il 6/4 cadenziale richiede obbligatoriamente il tempo forte per il suo peso cadenziale e la corretta risoluzione." },
  { q: "Cosa succede se un 6/4 cadenziale non è seguito da V?", opts: ["È accettabile in modo minore", "È un grave errore contrappuntistico — la risoluzione su V è obbligatoria", "Si può andare direttamente a I", "Si può andare a IV"], a: 1, fb: "Non risolvere I6/4 su V è un grave errore. Il 6/4 crea una forte tensione (quinta e quarta contro il basso) che esige la risoluzione sulla dominante. La formula è invariabilmente I6/4 → V → I." },
  { q: "Quale accordo rappresenta il basso in un 6/4 cadenziale in Do maggiore?", opts: ["Do (fondamentale di I)", "Mi (terza di I)", "Sol (quinta di I)", "Fa (sottodominante)"], a: 2, fb: "In I6/4 in Do maggiore, il basso è Sol (quinta di Do–Mi–Sol). È questa quinta al basso a creare l'instabilità caratteristica del 6/4 e a richiedere la risoluzione su V (che ha anch'esso Sol al basso)." },
  { q: "La nota di soprano è Mi in Do maggiore. Quali accordi possono contenere Mi?", opts: ["Solo I (Do–Mi–Sol)", "I (Do–Mi–Sol), III (Mi–Sol–Si), VIm (La–Do–Mi)", "Solo V (Sol–Si–Re)", "Solo IV (Fa–La–Do)"], a: 1, fb: "Mi può essere: la terza di I (Do–Mi–Sol), la fondamentale di III (Mi–Sol–Si), la quinta di VIm (La–Do–Mi). Il contesto armonico determina la scelta migliore." },
  { q: "La nota di soprano è Sol in Do maggiore. Quali accordi possono contenerla?", opts: ["Solo I, III, V", "I (quinta), III (terza), V (fondamentale) e a volte VIm", "I (quinta), V (fondamentale) e anche accordi che hanno Sol come fondamentale o quinta nella tonalità", "Solo V"], a: 2, fb: "Sol può essere: la quinta di I (Do–Mi–Sol), la fondamentale di V (Sol–Si–Re), la terza di Mi minore (III). La lista completa dipende dalla tonalità." },
  { q: "La nota di soprano è Si in Do maggiore. Quali accordi sono compatibili?", opts: ["Solo V (Sol–Si–Re)", "V (fondamentale Sol, terza Si), I (accordo di settima Do–Mi–Sol–Si), VIIdim (Si–Re–Fa)", "Solo III", "I, IV, V, VIIdim"], a: 1, fb: "Si può essere: la terza di V (Sol–Si–Re), la 7ª di I7 (Do–Mi–Sol–Si), o la fondamentale di VIIdim (Si–Re–Fa). V è la scelta più comune nello stile SATB." },
  { q: "Nel cercare accordi compatibili con una nota di soprano, quale criterio è prioritario?", opts: ["L'accordo che suona meglio isolatamente", "La nota di soprano deve essere fondamentale, terza, quinta o (a volte) settima dell'accordo scelto — nella tonalità", "L'accordo più semplice da realizzare", "L'accordo con più note in comune con il precedente"], a: 1, fb: "La nota di soprano deve essere una nota costitutiva dell'accordo (fondamentale, terza, quinta o settima nello stile SATB rigoroso). La tonalità e la logica funzionale guidano la scelta finale." },
  { q: "Che cos'è una nota di passaggio?", opts: ["Una nota tenuta da una misura all'altra", "Una nota estranea all'accordo che collega per moto congiunto due note armoniche", "Una nota ausiliare sopra o sotto una nota reale", "Una nota anticipata prima del tempo"], a: 1, fb: "La nota di passaggio è una nota non armonica che si inserisce per moto congiunto tra due note armoniche (es. Do–Re–Mi dove Re è di passaggio). Deve essere breve e non accentuata." },
  { q: "Che cos'è una nota ausiliare (bordura)?", opts: ["Una figura ornamentale attorno a una nota reale, che ritorna alla stessa nota", "Una nota di passaggio tra due armonie diverse", "Un ritardo nella risoluzione di una dissonanza", "Un'anticipazione della nota seguente"], a: 0, fb: "La nota ausiliare orbita attorno a una nota reale: nota reale → nota adiacente (semitono o tono) → ritorno alla nota reale. Es. Mi–Fa–Mi o Mi–Re#–Mi. La nota centrale è la nota armonica reale." },
  { q: "Che cos'è un ritardo?", opts: ["Una nota che arriva prima del suo accordo", "Una nota armonica prolungata oltre il cambio di accordo, creando una dissonanza risolta per moto congiunto discendente", "Una nota di passaggio non accentuata", "Una nota ausiliare a distanza di terza"], a: 1, fb: "Il ritardo è una nota tenuta dall'accordo precedente che si prolunga nel nuovo accordo, creando una dissonanza. Risolve obbligatoriamente per moto congiunto discendente. Es.: 4–3, 7–6, 9–8." },
  { q: "Che cos'è un'anticipazione?", opts: ["Una nota che arriva in anticipo appartenente all'accordo successivo", "Un ritardo risolto verso l'alto", "Una nota di passaggio su tempo forte", "Una nota ausiliare cromatica"], a: 0, fb: "L'anticipazione è una nota che appartiene all'accordo successivo ma arriva prima del cambio di accordo. È generalmente breve, non accentuata, e spesso su una levare o un tempo debole." },
  { q: "Perché bisogna identificare le note estranee prima di armonizzare un soprano?", opts: ["Per eliminarle dalla melodia", "Per non creare accordi errati su note non reali — armonizzare solo le note strutturali", "Per raddoppiarle nel tenore", "Per trasporle all'ottava"], a: 1, fb: "Armonizzare una nota di passaggio o ausiliare come se fosse armonica crea un accordo errato. Bisogna prima identificare le note estranee, poi armonizzare solo le note reali della melodia." },
  { q: "Nel soprano Sol–Fa–Mi (2 tempi su Sol, Fa molto breve, Mi), Fa è probabilmente:", opts: ["Una nota armonica reale da armonizzare", "Una nota di passaggio tra Sol e Mi — non creare un accordo su Fa", "Un ritardo di Sol", "Un'anticipazione di Mi"], a: 1, fb: "Fa breve tra Sol e Mi, per moto congiunto discendente, è tipicamente una nota di passaggio. Non cambiare accordo su Fa — mantenere l'armonia di Sol e cambiare su Mi." },
  { q: "In Do maggiore, il basso è Do–Si–La–Fa–Sol–Do. Quale armonizzazione corrisponde a I–V6–VI–IV–V–I?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "Do = I (fondamentale), Si = V6 (Si = terza di V al basso = 1° rivolto), La = VI, Fa = IV, Sol = V, Do = I. Progressione classica T–D–T–SD–D–T." },
  { q: "In Do maggiore, qual è il basso naturale per VI (La minore)?", opts: ["Do", "Mi", "La", "Sol"], a: 2, fb: "La è la fondamentale di VI (La–Do–Mi) in Do maggiore. La al basso = VI in posizione fondamentale. È l'accordo relativo minore, molto usato dopo I o V." },
  { q: "In Do maggiore, il basso Do–Mi–Sol–Mi–Do corrisponde a:", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "Do = I (fondamentale), Mi = I6 (primo rivolto), Sol = I6/4 (secondo rivolto), Mi = I6, Do = I. Restiamo sull'accordo di Do in posizioni diverse — arpeggio armonico." },
  { q: "La cadenza perfetta in Do maggiore è:", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "La cadenza perfetta = V → I. In Do maggiore: Sol–Si–Re → Do–Mi–Sol. Entrambi gli accordi devono essere in posizione fondamentale perché la cadenza sia 'perfetta' in senso stretto." },
  { q: "In Sol maggiore, la sensibile è:", opts: ["Fa naturale", "Fa#", "Do", "Mi"], a: 1, fb: "In Sol maggiore, la scala è Sol–La–Si–Do–Re–Mi–Fa#–Sol. La sensibile (7° grado) è Fa#. Al basso, Fa# impone V6 (Re–Fa#–La con Fa# al basso)." },
  { q: "In Sol maggiore, V6 al basso corrisponde a:", opts: ["Sol al basso", "Fa# al basso (terza dell'accordo di Re = V)", "Mi al basso", "Si al basso"], a: 1, fb: "In Sol maggiore, V = Re–Fa#–La. Fa# è la terza di quest'accordo. Fa# al basso = V6 (primo rivolto della dominante di Sol maggiore)." },
  { q: "In Sol maggiore, la progressione I–V–VI–IV–V–I con basso Sol–Re–Mi–Do–Re–Sol è:", opts: ["Errata — Re al basso non è V", "Corretta — Re è la fondamentale di V (Re–Fa#–La)", "Corretta ma V dovrebbe essere in primo rivolto", "Errata — Mi non corrisponde a VI"], a: 1, fb: "Sol = I (fondamentale), Re = V (fondamentale), Mi = VI (Mi–Sol–Si = VIm), Do = IV (Do–Mi–Sol), Re = V, Sol = I. Progressione T–D–T–SD–D–T, interamente corretta." },
  { q: "In Sol maggiore, l'accordo IV è:", opts: ["Do–Mi–Sol (Do maggiore)", "Re–Fa#–La", "Mi–Sol–Si", "La–Do–Mi"], a: 0, fb: "IV in Sol maggiore = Do–Mi–Sol (Do maggiore). Costruito sul 4° grado di Sol maggiore (Sol–La–Si–Do), l'accordo diatonico è Do–Mi–Sol. È la sottodominante di Sol." },
  { q: "In Re minore armonico, la sensibile è:", opts: ["Do naturale", "Do#", "Sib", "La"], a: 1, fb: "In Re minore armonico, la 7ª è alzata: Do naturale → Do#. Do# è la sensibile che sale a Re (tonica). Al basso, Do# impone V6 (La–Do#–Mi con Do# al basso)." },
  { q: "In Re minore, Sib al basso può corrispondere a:", opts: ["Solo IV", "bVI (Sib–Re–Fa = bVI in posizione fondamentale) o IV6 (Sol–Sib–Re con Sib al basso)", "Solo I", "V6"], a: 1, fb: "Sib al basso in Re minore può essere la fondamentale di bVI (Sib–Re–Fa, 6° grado abbassato) o la terza di IV (Sol–Sib–Re in primo rivolto). Entrambi sono possibili a seconda del contesto." },
  { q: "In Re minore, qual è il basso per V in posizione fondamentale?", opts: ["Re", "La", "Do#", "Sol"], a: 1, fb: "V in Re minore = La–Do#–Mi (dominante armonica). La è la fondamentale = La al basso = V in posizione fondamentale. La risoluzione La→Re è la cadenza perfetta in Re minore." },
  { q: "In Re minore, la progressione Im–V–bVI–IV–V–Im corrisponde al basso:", opts: ["Re–La–Sol–Sib–La–Re", "Re–La–Sib–Sol–La–Re", "La–Re–Sib–Sol–La–Re", "Re–La–Sib–Do#–La–Re"], a: 1, fb: "Im=Re, V=La, bVI=Sib (fondamentale di Sib–Re–Fa), IV=Sol (fondamentale di Sol–Sib–Re in Re minore), V=La, Im=Re. Basso: Re–La–Sib–Sol–La–Re." },
  { q: "Sulla stessa nota di basso, spesso ci sono 2–3 accordi possibili. Quale criterio permette di scegliere?", opts: ["Sempre lo stesso accordo indipendentemente dal contesto", "La logica funzionale (T→SD→D→T), la melodia del soprano e l'evitamento dei parallelismi", "L'accordo con meno note alterate", "L'accordo più acuto"], a: 1, fb: "La scelta tra più accordi possibili dipende dalla logica funzionale (progressione T→SD→D→T), dalla compatibilità con il soprano e dall'evitamento di quinte e ottave parallele." },
  { q: "La nota Re al basso in Do maggiore può essere: la fondamentale di II (Re–Fa–La) o la quinta di V (Sol–Si–Re). Cosa decide?", opts: ["Sempre II perché è la fondamentale", "La posizione nella frase: II prima di V (SD→D), V6/4 raramente usato; il soprano e il contesto cadenziale decidono", "Sempre V6/4", "Si sceglie a caso"], a: 1, fb: "Se Re al basso precede Sol o Mi, II (Re–Fa–La) è naturale come sottodominante. Se siamo alla fine di una frase cadenziale con Sol nel soprano, V6/4 può convenire. Il contesto decide." },
  { q: "Su La al basso in Do maggiore, quali sono gli accordi più frequenti?", opts: ["VIm (La–Do–Mi) o IV6 (Fa–La–Do con La al basso)", "Solo I o V", "III o VII", "V o II"], a: 0, fb: "La al basso può essere la fondamentale di VIm (La–Do–Mi, 6° grado) o la terza di IV (Fa–La–Do in primo rivolto = IV6). Il contesto armonico e la melodia del soprano guidano la scelta." },
  { q: "Che cos'è il ritmo armonico?", opts: ["La velocità con cui suona il batterista", "La frequenza con cui gli accordi cambiano in una progressione", "Il numero di voci nell'accordo", "La durata di ogni nota del soprano"], a: 1, fb: "Ritmo armonico = frequenza dei cambi di accordo. Veloce = un accordo per tempo o nota; lento = un accordo per misura o più misure. Deve essere adattato al tempo e allo stile." },
  { q: "Nello stile SATB rigoroso, bisogna cambiare accordo su ogni nota veloce del soprano?", opts: ["Sì, ogni nota deve avere il suo accordo", "No — le note veloci sono spesso note di passaggio o ausiliare; si cambia accordo sulle note lunghe/accentate", "Sì, ma solo nel soprano", "No, mai su due note consecutive"], a: 1, fb: "Cambiare accordo su ogni nota veloce è un errore tipico. Le note brevi sono spesso estranee. Il ritmo armonico segue il polso strutturale del brano — di solito la semiminima o la minima." },
  { q: "Qual è il segnale che si armonizza troppo velocemente (ritmo armonico troppo denso)?", opts: ["Accordi troppo stabili", "Frequenti errori di quinte o ottave parallele e cambi di accordo su note non armoniche", "Un soprano troppo acuto", "Troppi rivolti"], a: 1, fb: "Un ritmo armonico troppo denso porta a cambi di accordo su note estranee, generando dissonanze e parallelismi. La soluzione: identificare le note reali e armonizzare a una frequenza più lenta." },
  { q: "In 4/4, qual è un ritmo armonico frequente per un'armonizzazione di livello medio?", opts: ["Un accordo ogni 2 misure", "Un accordo per misura o un accordo ogni due tempi (mezza misura)", "Un accordo per nota (croma)", "Quattro accordi diversi per misura"], a: 1, fb: "In 4/4, il ritmo armonico standard è un accordo per misura o ogni due tempi. Questo ritmo lascia spazio alle note estranee senza provocare un'eccessiva armonizzazione." },
  { q: "Cosa significa la progressione T→SD→D→T nell'armonizzazione?", opts: ["Tonica verso sottodominante verso dominante verso tonica — il ciclo armonico fondamentale", "Tenuto, staccato, distaccato, tenuto", "Triplo, soprano, basso, tenore", "Terza, sesta, semitono, tono"], a: 0, fb: "T=Tonica (I, VI), SD=Sottodominante (IV, II), D=Dominante (V, VIIdim). La progressione naturale T→SD→D→T crea tensione e risoluzione. In Do maggiore: I–IV–V–I." },
  { q: "Qual è l'esempio tipico della progressione T→SD→D→T in Do maggiore?", opts: ["I–V–IV–I", "I–II6–V–I o I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I o I–II6–V–I sono le progressioni T→SD→D→T per eccellenza. La sottodominante (IV o II) precede la dominante (V) che risolve sulla tonica (I)." },
  { q: "La progressione IV–V–IV nell'armonizzazione è:", opts: ["Eccellente — alterna SD e D", "Da evitare — retrocessione da V a IV (D→SD) contro il flusso T→SD→D→T", "Neutra — né buona né cattiva", "Obbligatoria prima di qualsiasi cadenza"], a: 1, fb: "IV–V–IV è un errore di progressione: si retrocede da D (V) a SD (IV), contraddicendo il flusso naturale. La progressione deve avanzare: SD→D→T. Retrocedere indebolisce la logica tonale." },
  { q: "VI è generalmente classificato come:", opts: ["Dominante", "Tonica (sostituto di I)", "Sottodominante", "Accordo di passaggio"], a: 1, fb: "VI (La–Do–Mi in Do maggiore) è il relativo minore di I — condivide due note con I. Funziona come sostituto della Tonica e può sostituire I dopo una cadenza d'inganno (V→VI anziché V→I)." },
  { q: "II è generalmente classificato come:", opts: ["Tonica", "Sottodominante (condivide due note con IV)", "Dominante", "Neutro"], a: 1, fb: "II (Re–Fa–La in Do maggiore) è la sottodominante — condivide Fa e La con IV (Fa–La–Do). II6 è molto frequente nell'armonizzazione prima di V, creando la progressione SD→D." },
  { q: "La cadenza d'inganno (cadenza evitata) si verifica quando:", opts: ["V risolve su I come previsto", "V risolve su VI invece di I — sorpresa armonica", "IV risolve su V", "II va direttamente a I"], a: 1, fb: "Cadenza d'inganno = V→VI. Invece di risolvere su I, la dominante si dirige su VI (relativo minore). È una sorpresa che prolunga la frase e crea interesse. La risoluzione finale su I è differita." },
  { q: "In un'armonizzazione di basso dato, come avvicinarsi alla fine della frase?", opts: ["Finire su qualsiasi accordo", "Prevedere una cadenza chiara (V–I o IV–V–I) con gli accordi nel corretto ordine funzionale T→SD→D→T", "Finire sempre su VI per varietà", "Non usare V prima di I"], a: 1, fb: "La fine della frase deve essere pianificata: identificare la cadenza (V–I per cadenza perfetta, IV–I per cadenza plagale, V6/4–V–I per cadenza con 6/4), poi assicurarsi che la progressione vi conduca logicamente." },
  { q: "Quale regola fondamentale guida l'incatenamento degli accordi nell'armonizzazione?", opts: ["Qualsiasi accordo può seguire qualsiasi altro", "T può andare a SD o D; SD va a D o T; D va a T (o VI in cadenza d'inganno)", "Alternare sempre SD e D", "Gli accordi in rivolto non possono susseguirsi"], a: 1, fb: "La regola delle funzioni armoniche: T→SD, T→D, SD→D, D→T, D→VI (cadenza d'inganno). SD→T è la cadenza plagale. SD→SD e D→D sono possibili con moderazione." },
  { q: "Perché si evita la progressione V–IV nello stile SATB rigoroso?", opts: ["È troppo semplice", "Rappresenta una retrocessione da D a SD — contro il flusso armonico naturale; la sensibile (in V) cerca di salire, non di scendere verso IV", "Crea quinte aumentate", "Non esiste in Do maggiore"], a: 1, fb: "V→IV è una retrocessione (D→SD). La sensibile (Si in Do maggiore) nell'accordo di V vuole salire verso Do (I) — non risolve naturalmente su IV. Questa progressione indebolisce il senso tonale ed è evitata nello stile rigoroso." },
  { q: "Quale progressione è corretta tra due accordi di tonica?", opts: ["I – I (ripetizione vietata)", "I – VI – I o I – I6 – I (legittimi con la stessa fondamentale)", "I non può mai essere seguito da un altro accordo di tonica", "I deve sempre andare a IV o V"], a: 1, fb: "Si può passare da I a VI (sostituto di tonica) o da I a I6 (rivolto per movimento di basso). La ripetizione identica I–I è sterile ma non un errore. L'importante è la progressione globale." },
  { q: "Nell'armonizzazione, cos'è un 'raddoppio' e quale regola si applica in posizione fondamentale?", opts: ["Suonare con due strumenti — raddoppiare liberamente qualsiasi accordo", "Ripetere una nota dell'accordo in un'altra voce — in posizione fondamentale, raddoppiare preferibilmente la fondamentale", "Aggiungere una settima all'accordo", "Ripetere l'accordo per due misure di fila"], a: 1, fb: "Il raddoppio = scrivere la stessa altezza in due voci diverse (all'ottava o all'unisono). In posizione fondamentale, si raddoppia preferibilmente la fondamentale. Si evita di raddoppiare la sensibile (che deve salire) e la terza (colore dell'accordo)." },
];

const questionsPt: Question[] = [
  { q: "Uma nota de baixo é a fundamental do acorde. Em que posição está esse acorde?", opts: ["Primeira inversão", "Segunda inversão", "Posição fundamental", "Terceira inversão"], a: 2, fb: "Quando o baixo é a fundamental do acorde, o acorde está na posição fundamental (posição de base). É a posição mais estável, preferida nos tempos fortes e nas cadências." },
  { q: "Se a nota de baixo é a terça de um acorde, qual é a inversão?", opts: ["Posição fundamental", "Primeira inversão (acorde de sexta)", "Segunda inversão (6/4)", "Posição de quinta"], a: 1, fb: "Terça no baixo = primeira inversão, notada como 'acorde de sexta' (cifragem: 6). Por exemplo, Dó–Mi–Sol com Mi no baixo dá um acorde de Dó em primeira inversão." },
  { q: "Se a nota de baixo é a quinta de um acorde, qual é a inversão?", opts: ["Posição fundamental", "Primeira inversão", "Segunda inversão (acorde de quarta e sexta)", "Posição aberta"], a: 2, fb: "Quinta no baixo = segunda inversão, notada '6/4' (cifragem: 6 e 4). É a inversão mais instável — exige uma resolução cuidadosa, especialmente como 6/4 cadencial." },
  { q: "O acorde Dó–Mi–Sol com Sol no baixo corresponde a:", opts: ["I na posição fundamental", "I na primeira inversão", "I na segunda inversão", "V6"], a: 2, fb: "Sol é a quinta do acorde de Dó maior. Sol no baixo = segunda inversão = I6/4 (Dó 6/4). Este acorde é muito instável e aparece principalmente como 6/4 cadencial." },
  { q: "O acorde Sol–Si–Ré com Si no baixo é:", opts: ["V na posição fundamental", "V6 (primeira inversão de V)", "V6/4 (segunda inversão)", "VII na posição fundamental"], a: 1, fb: "Si é a terça do acorde de Sol maior. Si no baixo = primeira inversão de V = V6. Esta inversão é muito comum e produz um baixo por graus elegante." },
  { q: "Como fundamental de qual acorde pode Sol no baixo servir?", opts: ["Apenas o acorde de Dó maior", "Acorde de Sol maior (V), Sol menor, Sol7, etc.", "Acorde de Mi menor", "Acorde de Fá maior"], a: 1, fb: "Sol no baixo pode ser a fundamental de V (Sol–Si–Ré), Solm, Sol7, etc. Por isso é necessário analisar a tonalidade e o contexto antes de decidir o acorde." },
  { q: "Quando a nota de baixo é Sol em Dó maior, quais acordes são possíveis com Sol como fundamental?", opts: ["Apenas I, IV, II", "V (Sol–Si–Ré) e VII (com cor diminuta) principalmente", "Apenas I6/4", "Apenas I na posição fundamental"], a: 1, fb: "Em Dó maior, Sol no baixo como fundamental dá principalmente V (Sol–Si–Ré). Sol também pode ser a quinta de I (Dó–Mi–Sol) na segunda inversão, ou a terça de Mi menor." },
  { q: "Se o baixo é a sensível (7º grau) em Dó maior, qual acorde é obrigatório?", opts: ["VII diminuto na posição fundamental", "V6 (primeira inversão de V)", "IV6", "I6"], a: 1, fb: "A sensível (Si em Dó maior) no baixo impõe obrigatoriamente V6 — a primeira inversão do acorde de dominante. A sensível não pode ser fundamental no baixo no estilo rigoroso." },
  { q: "Por que a sensível no baixo dá V6 e não VIIdim na posição fundamental?", opts: ["Para evitar a quinta diminuta no baixo", "Porque VIIdim na posição fundamental cria um baixo instável com quinta diminuta difícil de dobrar e resolver", "Por convenção arbitrária", "Porque V6 é mais fácil de tocar"], a: 1, fb: "VIIdim na posição fundamental (Si–Ré–Fá) com Si no baixo produz uma quinta diminuta demasiado instável. O estilo SATB rigoroso impõe V6: a sensível (Si) é a terça de Sol–Si–Ré, criando uma harmonia de dominante natural." },
  { q: "Em Sol maior, a sensível é Fá#. Se Fá# está no baixo, o acorde é:", opts: ["VII na posição fundamental", "V6 em Sol maior", "II6", "IV6"], a: 1, fb: "Em Sol maior, a sensível é Fá#. Fá# no baixo = terça do acorde de Ré (V) = V6 em Sol maior. A regra é absoluta: sensível no baixo = V6." },
  { q: "Em Ré menor, a sensível é Dó#. Se Dó# está no baixo, o acorde é:", opts: ["VII diminuto na posição fundamental", "V6 em Ré menor (menor harmónico com sensível elevada)", "IV em Ré menor", "I6"], a: 1, fb: "Em Ré menor, a sensível harmónica é Dó# (elevada). Dó# no baixo = terça de Lá–Dó#–Mi (V) = V6 em Ré menor. A regra é idêntica no modo menor." },
  { q: "Em Dó maior, Fá é o 4º grau. Quais acordes são possíveis com Fá no baixo?", opts: ["Apenas I ou V", "IV na posição fundamental (Fá–Lá–Dó) ou II6 (Ré–Fá–Lá com Fá no baixo)", "Apenas III6 ou VII", "V7 ou I6/4"], a: 1, fb: "Fá no baixo em Dó maior pode ser: a fundamental de IV (Fá–Lá–Dó na posição fundamental) ou a terça de II (Ré–Fá–Lá na primeira inversão = II6). Ambos são frequentes conforme o contexto harmónico." },
  { q: "Qual é a diferença de efeito entre IV na posição fundamental e II6 quando Fá está no baixo?", opts: ["Nenhuma diferença", "IV é mais estável (fundamental no baixo), II6 traz uma cor mais móvel em direção a V", "II6 é mais estável", "IV sempre resolve em I, II6 nunca"], a: 1, fb: "IV (Fá–Lá–Dó) é estável na posição fundamental. II6 (Ré–Fá–Lá) com Fá no baixo é móvel — a sua resolução natural para V cria uma progressão SD→D mais dinâmica." },
  { q: "Sobre o 4º grau no baixo, qual escolha é preferível para preparar uma cadência V–I?", opts: ["IV na posição fundamental", "II6 — pois aponta mais diretamente para V", "I6/4 — para reforçar a cadência", "VII6"], a: 1, fb: "II6 com Fá no baixo resolve muito naturalmente em V. A sua terça (Ré) e a sua fundamental (nas vozes superiores) preparam eficazmente a dominante. Esta é a progressão II6–V–I, muito frequente." },
  { q: "Em que tipo de tempo pode aparecer o 6/4 cadencial?", opts: ["Em qualquer tempo", "Apenas num tempo forte", "Apenas num tempo fraco", "Apenas numa anacruse"], a: 1, fb: "O 6/4 cadencial (I6/4 = quinta de I no baixo) aparece exclusivamente num tempo forte. A sua resolução em V deve ser imediata, no tempo seguinte." },
  { q: "Após um 6/4 cadencial (I6/4 num tempo forte), qual acorde DEVE seguir imediatamente?", opts: ["I na posição fundamental", "IV", "V (dominante)", "VI"], a: 2, fb: "O 6/4 cadencial resolve OBRIGATORIAMENTE em V. A sequência é: I6/4 (tempo forte) → V → I. Saltar a resolução em V ou ir para outro acorde é uma falta grave." },
  { q: "A progressão correta com um 6/4 cadencial em Dó maior é:", opts: ["I – I6/4 – IV – V – I", "I – IV – I6/4 – V – I", "I – I6/4 – II – V – I", "I – IV – V – I6/4 – I"], a: 1, fb: "I – IV – I6/4 – V – I é a progressão cadencial típica. O I6/4 aparece no tempo forte antes da dominante. 'Pesa' sobre a quinta da tónica e resolve em V." },
  { q: "Pode-se colocar um 6/4 cadencial num tempo fraco?", opts: ["Sim, é até recomendado", "Não — o 6/4 cadencial é reservado exclusivamente para os tempos fortes", "Sim, mas apenas no modo menor", "Sim, se o acorde seguinte for IV"], a: 1, fb: "Não — é uma falta característica colocar um 6/4 cadencial num tempo fraco. O 6/4 cadencial exige obrigatoriamente o tempo forte para ter o seu peso cadencial e a resolução correta." },
  { q: "O que acontece se um 6/4 cadencial não for seguido de V?", opts: ["É aceitável no modo menor", "É uma falta grave de contraponto — a resolução em V é obrigatória", "Pode-se ir diretamente a I", "Pode-se ir a IV"], a: 1, fb: "Não resolver I6/4 em V é uma falta grave. O 6/4 cria uma forte tensão (quinta e quarta contra o baixo) que exige resolução na dominante. A fórmula é invariavelmente I6/4 → V → I." },
  { q: "Que acorde representa o baixo num 6/4 cadencial em Dó maior?", opts: ["Dó (fundamental de I)", "Mi (terça de I)", "Sol (quinta de I)", "Fá (subdominante)"], a: 2, fb: "Em I6/4 em Dó maior, o baixo é Sol (quinta de Dó–Mi–Sol). É esta quinta no baixo que cria a instabilidade característica do 6/4 e exige a resolução em V (que também tem Sol no baixo)." },
  { q: "A nota de soprano é Mi em Dó maior. Quais acordes podem conter Mi?", opts: ["Apenas I (Dó–Mi–Sol)", "I (Dó–Mi–Sol), III (Mi–Sol–Si), VIm (Lá–Dó–Mi)", "Apenas V (Sol–Si–Ré)", "Apenas IV (Fá–Lá–Dó)"], a: 1, fb: "Mi pode ser: a terça de I (Dó–Mi–Sol), a fundamental de III (Mi–Sol–Si), a quinta de VIm (Lá–Dó–Mi). O contexto harmónico determina a melhor escolha." },
  { q: "A nota de soprano é Sol em Dó maior. Quais acordes podem contê-la?", opts: ["Apenas I, III, V", "I (quinta), III (terça), V (fundamental) e às vezes VIm", "I (quinta), V (fundamental) e também acordes que têm Sol como fundamental ou quinta na tonalidade", "Apenas V"], a: 2, fb: "Sol pode ser: a quinta de I (Dó–Mi–Sol), a fundamental de V (Sol–Si–Ré), a terça de Mi menor (III). A lista completa depende da tonalidade." },
  { q: "A nota de soprano é Si em Dó maior. Quais acordes são compatíveis?", opts: ["Apenas V (Sol–Si–Ré)", "V (fundamental Sol, terça Si), I (acorde de sétima Dó–Mi–Sol–Si), VIIdim (Si–Ré–Fá)", "Apenas III", "I, IV, V, VIIdim"], a: 1, fb: "Si pode ser: a terça de V (Sol–Si–Ré), a 7ª de I7 (Dó–Mi–Sol–Si), ou a fundamental de VIIdim (Si–Ré–Fá). V é a escolha mais comum no estilo SATB." },
  { q: "Ao procurar acordes compatíveis com uma nota de soprano, qual critério é prioritário?", opts: ["O acorde que soa melhor isoladamente", "A nota de soprano deve ser fundamental, terça, quinta ou (às vezes) sétima do acorde escolhido — na tonalidade", "O acorde mais simples de realizar", "O acorde com mais notas em comum com o anterior"], a: 1, fb: "A nota de soprano deve ser uma nota constitutiva do acorde (fundamental, terça, quinta ou sétima no estilo SATB rigoroso). A tonalidade e a lógica funcional orientam a escolha final." },
  { q: "O que é uma nota de passagem?", opts: ["Uma nota sustentada de um compasso ao seguinte", "Uma nota estranha ao acorde que une por movimento conjunto duas notas harmónicas", "Uma nota auxiliar acima ou abaixo de uma nota real", "Uma nota antecipada antes do tempo"], a: 1, fb: "A nota de passagem é uma nota não harmónica que se desliza por movimento conjunto entre duas notas harmónicas (ex. Dó–Ré–Mi onde Ré é de passagem). Deve ser breve e não acentuada." },
  { q: "O que é uma nota auxiliar (bordadura)?", opts: ["Uma figura ornamental em torno de uma nota real, regressando à mesma nota", "Uma nota de passagem entre duas harmonias diferentes", "Um retardo na resolução de uma dissonância", "Uma antecipação da nota seguinte"], a: 0, fb: "A nota auxiliar orbita em torno de uma nota real: nota real → nota adjacente (semitom ou tom) → retorno à nota real. Ex. Mi–Fá–Mi ou Mi–Ré#–Mi. A nota central é a nota harmónica real." },
  { q: "O que é um retardo?", opts: ["Uma nota que chega antes do seu acorde", "Uma nota harmónica prolongada além da mudança de acorde, criando uma dissonância resolvida por movimento conjunto descendente", "Uma nota de passagem não acentuada", "Uma nota auxiliar a distância de terça"], a: 1, fb: "O retardo é uma nota sustentada desde o acorde anterior que se prolonga no novo acorde, criando uma dissonância. Resolve obrigatoriamente por movimento conjunto descendente. Ex.: 4–3, 7–6, 9–8." },
  { q: "O que é uma antecipação?", opts: ["Uma nota que chega cedo pertencendo ao próximo acorde", "Um retardo resolvido para cima", "Uma nota de passagem num tempo forte", "Uma nota auxiliar cromática"], a: 0, fb: "A antecipação é uma nota que pertence ao acorde seguinte mas chega antes da mudança de acorde. Geralmente é breve, não acentuada, e frequentemente numa anacruse ou tempo fraco." },
  { q: "Por que se deve identificar as notas estranhas antes de harmonizar um soprano?", opts: ["Para as suprimir da melodia", "Para não criar acordes incorretos sobre notas não reais — harmonizar apenas as notas estruturais", "Para as dobrar no tenor", "Para as transpor à oitava"], a: 1, fb: "Harmonizar uma nota de passagem ou auxiliar como se fosse harmónica cria um acorde incorreto. Primeiro identificar as notas estranhas, depois harmonizar apenas as notas reais da melodia." },
  { q: "No soprano Sol–Fá–Mi (2 tempos em Sol, Fá muito breve, Mi), Fá é provavelmente:", opts: ["Uma nota harmónica real a harmonizar", "Uma nota de passagem entre Sol e Mi — não criar um acorde em Fá", "Um retardo de Sol", "Uma antecipação de Mi"], a: 1, fb: "Fá breve entre Sol e Mi, por movimento conjunto descendente, é tipicamente uma nota de passagem. Não mudar o acorde em Fá — manter a harmonia de Sol e mudar em Mi." },
  { q: "Em Dó maior, o baixo é Dó–Si–Lá–Fá–Sol–Dó. Qual harmonização corresponde a I–V6–VI–IV–V–I?", opts: ["I–IV–VI–V–V–I", "I–V6–VI–IV–V–I", "I–VII–VI–IV–V6–I", "I6–V–VI–IV–V–I"], a: 1, fb: "Dó = I (fundamental), Si = V6 (Si = terça de V no baixo = 1.ª inversão), Lá = VI, Fá = IV, Sol = V, Dó = I. Progressão clássica T–D–T–SD–D–T." },
  { q: "Em Dó maior, qual é o baixo natural para VI (Lá menor)?", opts: ["Dó", "Mi", "Lá", "Sol"], a: 2, fb: "Lá é a fundamental de VI (Lá–Dó–Mi) em Dó maior. Lá no baixo = VI na posição fundamental. É o acorde relativo menor, muito usado depois de I ou V." },
  { q: "Em Dó maior, o baixo Dó–Mi–Sol–Mi–Dó corresponde a:", opts: ["I – V6 – V – III6 – I", "I – I6 – I6/4 – I6 – I", "I – III – V – III – I", "I – I6 – V – I6 – I"], a: 1, fb: "Dó = I (fundamental), Mi = I6 (primeira inversão), Sol = I6/4 (segunda inversão), Mi = I6, Dó = I. Permanecemos no acorde de Dó com diferentes posições — arpejo harmónico." },
  { q: "A cadência perfeita em Dó maior é:", opts: ["IV – V – I", "V – I", "I – IV – I", "VI – V – I"], a: 1, fb: "A cadência perfeita = V → I. Em Dó maior: Sol–Si–Ré → Dó–Mi–Sol. Ambos os acordes devem estar na posição fundamental para que a cadência seja 'perfeita' no sentido estrito." },
  { q: "Em Sol maior, a sensível é:", opts: ["Fá natural", "Fá#", "Dó", "Mi"], a: 1, fb: "Em Sol maior, a escala é Sol–Lá–Si–Dó–Ré–Mi–Fá#–Sol. A sensível (7º grau) é Fá#. No baixo, Fá# impõe V6 (Ré–Fá#–Lá com Fá# no baixo)." },
  { q: "Em Sol maior, V6 no baixo corresponde a:", opts: ["Sol no baixo", "Fá# no baixo (terça do acorde de Ré = V)", "Mi no baixo", "Si no baixo"], a: 1, fb: "Em Sol maior, V = Ré–Fá#–Lá. Fá# é a terça deste acorde. Fá# no baixo = V6 (primeira inversão da dominante de Sol maior)." },
  { q: "Em Sol maior, a progressão I–V–VI–IV–V–I com baixo Sol–Ré–Mi–Dó–Ré–Sol é:", opts: ["Incorreta — Ré no baixo não é V", "Correta — Ré é a fundamental de V (Ré–Fá#–Lá)", "Correta mas V deveria estar na primeira inversão", "Incorreta — Mi não corresponde a VI"], a: 1, fb: "Sol = I (fundamental), Ré = V (fundamental), Mi = VI (Mi–Sol–Si = VIm), Dó = IV (Dó–Mi–Sol), Ré = V, Sol = I. Progressão T–D–T–SD–D–T, inteiramente correta." },
  { q: "Em Sol maior, o acorde IV é:", opts: ["Dó–Mi–Sol (Dó maior)", "Ré–Fá#–Lá", "Mi–Sol–Si", "Lá–Dó–Mi"], a: 0, fb: "IV em Sol maior = Dó–Mi–Sol (Dó maior). Construído sobre o 4º grau de Sol maior (Sol–Lá–Si–Dó), o acorde diatónico é Dó–Mi–Sol. É a subdominante de Sol." },
  { q: "Em Ré menor harmónico, a sensível é:", opts: ["Dó natural", "Dó#", "Sib", "Lá"], a: 1, fb: "Em Ré menor harmónico, a 7ª é elevada: Dó natural → Dó#. Dó# é a sensível que sobe para Ré (tónica). No baixo, Dó# impõe V6 (Lá–Dó#–Mi com Dó# no baixo)." },
  { q: "Em Ré menor, Sib no baixo pode corresponder a:", opts: ["Apenas IV", "bVI (Sib–Ré–Fá = bVI na posição fundamental) ou IV6 (Sol–Sib–Ré com Sib no baixo)", "Apenas I", "V6"], a: 1, fb: "Sib no baixo em Ré menor pode ser a fundamental de bVI (Sib–Ré–Fá, 6º grau bemolizado) ou a terça de IV (Sol–Sib–Ré na primeira inversão). Ambos são possíveis conforme o contexto." },
  { q: "Em Ré menor, qual é o baixo para V na posição fundamental?", opts: ["Ré", "Lá", "Dó#", "Sol"], a: 1, fb: "V em Ré menor = Lá–Dó#–Mi (dominante harmónica). Lá é a fundamental = Lá no baixo = V na posição fundamental. A resolução Lá→Ré é a cadência perfeita em Ré menor." },
  { q: "Em Ré menor, a progressão Im–V–bVI–IV–V–Im corresponde ao baixo:", opts: ["Ré–Lá–Sol–Sib–Lá–Ré", "Ré–Lá–Sib–Sol–Lá–Ré", "Lá–Ré–Sib–Sol–Lá–Ré", "Ré–Lá–Sib–Dó#–Lá–Ré"], a: 1, fb: "Im=Ré, V=Lá, bVI=Sib (fundamental de Sib–Ré–Fá), IV=Sol (fundamental de Sol–Sib–Ré em Ré menor), V=Lá, Im=Ré. Baixo: Ré–Lá–Sib–Sol–Lá–Ré." },
  { q: "Sobre a mesma nota de baixo, frequentemente há 2–3 acordes possíveis. Qual critério permite escolher?", opts: ["Sempre o mesmo acorde independentemente do contexto", "A lógica funcional (T→SD→D→T), a melodia do soprano e a evitação dos paralelismos", "O acorde com menos notas alteradas", "O acorde mais agudo"], a: 1, fb: "A escolha entre vários acordes possíveis depende da lógica funcional (progressão T→SD→D→T), da compatibilidade com o soprano e da evitação de quintas e oitavas paralelas." },
  { q: "A nota Ré no baixo em Dó maior pode ser: a fundamental de II (Ré–Fá–Lá) ou a quinta de V (Sol–Si–Ré). O que decide?", opts: ["Sempre II porque é a fundamental", "A posição na frase: II antes de V (SD→D), V6/4 raramente usado; o soprano e o contexto cadencial decidem", "Sempre V6/4", "Escolhe-se ao acaso"], a: 1, fb: "Se Ré no baixo precede Sol ou Mi, II (Ré–Fá–Lá) é natural como subdominante. Se estamos no final de uma frase cadencial com Sol no soprano, V6/4 pode convir. O contexto decide." },
  { q: "Sobre Lá no baixo em Dó maior, quais são os acordes mais frequentes?", opts: ["VIm (Lá–Dó–Mi) ou IV6 (Fá–Lá–Dó com Lá no baixo)", "Apenas I ou V", "III ou VII", "V ou II"], a: 0, fb: "Lá no baixo pode ser a fundamental de VIm (Lá–Dó–Mi, 6º grau) ou a terça de IV (Fá–Lá–Dó na primeira inversão = IV6). O contexto harmónico e a melodia do soprano orientam a escolha." },
  { q: "O que é o ritmo harmónico?", opts: ["A velocidade com que o baterista toca", "A frequência com que os acordes mudam numa progressão", "O número de vozes no acorde", "A duração de cada nota do soprano"], a: 1, fb: "Ritmo harmónico = frequência das mudanças de acorde. Rápido = um acorde por tempo ou nota; lento = um acorde por compasso ou vários compassos. Deve ser adaptado ao andamento e ao estilo." },
  { q: "No estilo SATB rigoroso, deve-se mudar de acorde em cada nota rápida do soprano?", opts: ["Sim, cada nota deve ter o seu acorde", "Não — as notas rápidas são frequentemente notas de passagem ou auxiliares; muda-se de acorde nas notas longas/acentuadas", "Sim, mas apenas no soprano", "Não, nunca em duas notas consecutivas"], a: 1, fb: "Mudar de acorde em cada nota rápida é uma falta típica. As notas breves são frequentemente estranhas. O ritmo harmónico segue o pulso estrutural da peça — geralmente a semínima ou a mínima." },
  { q: "Qual é o sinal de que se harmoniza demasiado rápido (ritmo harmónico demasiado denso)?", opts: ["Acordes demasiado estáveis", "Frequentes faltas de quintas ou oitavas paralelas e mudanças de acorde sobre notas não harmónicas", "Um soprano demasiado agudo", "Demasiadas inversões"], a: 1, fb: "Um ritmo harmónico demasiado denso leva a mudanças de acorde sobre notas estranhas, gerando dissonâncias e paralelismos. A solução: identificar as notas reais e harmonizar a uma frequência mais lenta." },
  { q: "Em 4/4, qual é um ritmo harmónico frequente para uma harmonização de nível médio?", opts: ["Um acorde a cada 2 compassos", "Um acorde por compasso ou um acorde a cada dois tempos (meio compasso)", "Um acorde por nota (colcheia)", "Quatro acordes diferentes por compasso"], a: 1, fb: "Em 4/4, o ritmo harmónico padrão é um acorde por compasso ou a cada dois tempos. Este ritmo deixa espaço às notas estranhas sem provocar sobre-harmonização." },
  { q: "O que significa a progressão T→SD→D→T na harmonização?", opts: ["Tónica para subdominante para dominante para tónica — o ciclo harmónico fundamental", "Tenuto, staccato, destacado, tenuto", "Triple, soprano, baixo, tenor", "Terça, sexta, semitom, tom"], a: 0, fb: "T=Tónica (I, VI), SD=Subdominante (IV, II), D=Dominante (V, VIIdim). A progressão natural T→SD→D→T cria tensão e resolução. Em Dó maior: I–IV–V–I." },
  { q: "Qual é o exemplo típico da progressão T→SD→D→T em Dó maior?", opts: ["I–V–IV–I", "I–II6–V–I ou I–IV–V–I", "IV–I–V–I", "VI–IV–I–V"], a: 1, fb: "I–IV–V–I ou I–II6–V–I são as progressões T→SD→D→T por excelência. A subdominante (IV ou II) precede a dominante (V) que resolve na tónica (I)." },
  { q: "A progressão IV–V–IV na harmonização é:", opts: ["Excelente — alterna SD e D", "A evitar — retrocesso de V a IV (D→SD) contra o fluxo T→SD→D→T", "Neutra — nem boa nem má", "Obrigatória antes de qualquer cadência"], a: 1, fb: "IV–V–IV é uma falta de progressão: retrocede-se de D (V) para SD (IV), contradizendo o fluxo natural. A progressão deve avançar: SD→D→T. Retroceder enfraquece a lógica tonal." },
  { q: "VI é geralmente classificado como:", opts: ["Dominante", "Tónica (substituto de I)", "Subdominante", "Acorde de passagem"], a: 1, fb: "VI (Lá–Dó–Mi em Dó maior) é o relativo menor de I — partilha duas notas com I. Funciona como substituto da Tónica e pode substituir I após uma cadência de engano (V→VI em vez de V→I)." },
  { q: "II é geralmente classificado como:", opts: ["Tónica", "Subdominante (partilha duas notas com IV)", "Dominante", "Neutro"], a: 1, fb: "II (Ré–Fá–Lá em Dó maior) é a subdominante — partilha Fá e Lá com IV (Fá–Lá–Dó). II6 é muito frequente na harmonização antes de V, criando a progressão SD→D." },
  { q: "A cadência de engano (cadência interrompida) ocorre quando:", opts: ["V resolve em I como esperado", "V resolve em VI em vez de I — surpresa harmónica", "IV resolve em V", "II vai diretamente a I"], a: 1, fb: "Cadência de engano = V→VI. Em vez de resolver em I, a dominante dirige-se para VI (relativo menor). É uma surpresa que prolonga a frase e cria interesse. A resolução final em I é adiada." },
  { q: "Numa harmonização de baixo dado, como abordar o final da frase?", opts: ["Terminar em qualquer acorde", "Prever uma cadência clara (V–I ou IV–V–I) com os acordes na ordem funcional correta T→SD→D→T", "Terminar sempre em VI para variedade", "Nunca usar V antes de I"], a: 1, fb: "O final da frase deve ser planeado: identificar a cadência (V–I para cadência perfeita, IV–I para cadência plagal, V6/4–V–I para cadência com 6/4), depois assegurar que a progressão conduz logicamente até lá." },
  { q: "Qual regra fundamental orienta o encadeamento dos acordes na harmonização?", opts: ["Qualquer acorde pode seguir qualquer outro", "T pode ir para SD ou D; SD vai para D ou T; D vai para T (ou VI em cadência de engano)", "Alternar sempre SD e D", "Os acordes em inversão não podem suceder-se"], a: 1, fb: "A regra das funções harmónicas: T→SD, T→D, SD→D, D→T, D→VI (cadência de engano). SD→T é a cadência plagal. SD→SD e D→D são possíveis com moderação." },
  { q: "Por que se evita a progressão V–IV no estilo SATB rigoroso?", opts: ["É demasiado simples", "Representa um retrocesso de D para SD — contra o fluxo harmónico natural; a sensível (em V) procura subir, não descer para IV", "Cria quintas aumentadas", "Não existe em Dó maior"], a: 1, fb: "V→IV é um retrocesso (D→SD). A sensível (Si em Dó maior) no acorde de V quer subir para Dó (I) — não resolve naturalmente em IV. Esta progressão enfraquece o sentido tonal e é evitada no estilo rigoroso." },
  { q: "Que progressão é correta entre dois acordes de tónica?", opts: ["I – I (repetição proibida)", "I – VI – I ou I – I6 – I (legítimos com a mesma fundamental)", "I nunca pode ser seguido de outro acorde de tónica", "I deve sempre ir a IV ou V"], a: 1, fb: "Pode-se passar de I para VI (substituto de tónica) ou de I para I6 (inversão para movimento de baixo). A repetição idêntica I–I é estéril mas não é uma falta. O importante é a progressão global." },
  { q: "Na harmonização, o que é um 'dobramento' e que regra se aplica na posição fundamental?", opts: ["Tocar com dois instrumentos — dobrar livremente qualquer acorde", "Repetir uma nota do acorde noutra voz — na posição fundamental, dobrar preferencialmente a fundamental", "Acrescentar uma sétima ao acorde", "Repetir o acorde por dois compassos seguidos"], a: 1, fb: "O dobramento = escrever a mesma altura em duas vozes diferentes (à oitava ou uníssono). Na posição fundamental, dobra-se preferencialmente a fundamental. Evita-se dobrar a sensível (que deve subir) e a terça (cor do acorde)." },
];

